import type { Context } from "hono";
import { normalizePublicBasePath } from "./config";
import { ensureControlUiAllowedOrigins } from "./control-ui";
import type { InstanceRecord } from "./instances";
import { runCommandText } from "./node-process";
import { openclawEnv, readInstanceConfig, usesSystemOpenclaw } from "./openclaw-instance";
import { probeInstanceRuntime, reconcileInstanceRuntime } from "./runtime-state";

/** 版本号缓存：binaryPath -> { version, fetchedAt } */
const versionCache = new Map<string, { version: string; fetchedAt: number }>();
const VERSION_CACHE_TTL_MS = 300_000; // 5 分钟

export interface InstanceStatusPayload {
  instanceId: string;
  ownerId: string;
  displayName: string;
  proxyBasePath: string;
  systemMode: boolean;
  installed: boolean;
  running: boolean;
  version: string | null;
  binaryPath: string | null;
  port: number | null;
  startedAt: number | null;
  dashboardUrl: string | null;
  dashboardTokenizedUrl: string | null;
  proxyDashboardUrl: string | null;
  proxyDashboardTokenizedUrl: string | null;
  gatewayTokenPresent: boolean;
}

async function runCommand(
  instance: InstanceRecord,
  cmd: string[]
): Promise<{ stdout: string; stderr: string; exitCode: number }> {
  return runCommandText(cmd, {
    env: openclawEnv(instance),
  });
}

function requestOrigin(c: Context): string {
  const url = new URL(c.req.url);
  const forwardedProto = c.req.header("x-forwarded-proto")?.split(",")[0]?.trim();
  const forwardedHost = c.req.header("x-forwarded-host")?.split(",")[0]?.trim();
  if (forwardedHost) {
    return `${(forwardedProto || url.protocol.replace(/:$/, "")).replace(/:$/, "")}://${forwardedHost}`;
  }
  return url.origin;
}

function buildBootstrapUrl(pageUrl: string, token: string): string {
  const bootstrapUrl = new URL(pageUrl);
  bootstrapUrl.searchParams.set("token", token);
  return bootstrapUrl.toString();
}

function requestHostname(c: Context): string {
  const forwardedHost = c.req.header("x-forwarded-host")?.split(",")[0]?.trim();
  const host = forwardedHost || c.req.header("host")?.split(",")[0]?.trim();
  if (host) {
    try {
      return new URL(`http://${host}`).hostname;
    } catch {
      return host;
    }
  }
  return "127.0.0.1";
}

export async function getInstanceStatus(instance: InstanceRecord, c: Context): Promise<InstanceStatusPayload> {
  let installed = false;
  let running = false;
  let version: string | null = null;
  let binaryPath: string | null = null;
  let port: number | null = null;
  let startedAt: number | null = null;
  let dashboardUrl: string | null = null;
  let dashboardTokenizedUrl: string | null = null;
  let proxyDashboardUrl: string | null = null;
  let proxyDashboardTokenizedUrl: string | null = null;
  let gatewayTokenPresent = false;


  const runtime = await probeInstanceRuntime(instance);
  installed = runtime.installed;
  binaryPath = runtime.binaryPath;
  port = runtime.port;
  running = runtime.running;
  startedAt = runtime.startedAt;

  if (installed && binaryPath) {
    const now = Date.now();
    const cached = versionCache.get(binaryPath);

    if (cached && now - cached.fetchedAt < VERSION_CACHE_TTL_MS) {
      version = cached.version;
    } else {
      try {
        const ver = await runCommand(instance, [binaryPath, "--version"]);
        if (ver.exitCode === 0) {
          version = ver.stdout;
          versionCache.set(binaryPath, { version, fetchedAt: now });
        }
      } catch {
        // ignore version failures
      }
    }
  }

  await reconcileInstanceRuntime(instance, runtime);

  if (installed) {
    await ensureControlUiAllowedOrigins(instance, {
      url: c.req.url,
      getHeader: (name) => c.req.header(name),
    });
    const config = await readInstanceConfig(instance);
    const gateway = (config.gateway as Record<string, unknown> | undefined) || {};
    const controlUi = (gateway.controlUi as Record<string, unknown> | undefined) || {};
    const auth = (gateway.auth as Record<string, unknown> | undefined) || {};
    const configuredUiBasePath = normalizePublicBasePath(
      typeof controlUi.basePath === "string" && controlUi.basePath.length > 0
        ? controlUi.basePath
        : "/"
    );
    const proxyUiBasePath = normalizePublicBasePath(instance.proxyBasePath);
    proxyDashboardUrl = new URL(proxyUiBasePath, `${requestOrigin(c)}/`).toString();

    if (port) {
      const directOrigin = `${new URL(c.req.url).protocol}//${requestHostname(c)}:${port}`;
      dashboardUrl = new URL(configuredUiBasePath, `${directOrigin}/`).toString();
    }

    const token = typeof process.env.OPENCLAW_GATEWAY_TOKEN === "string" && process.env.OPENCLAW_GATEWAY_TOKEN.length > 0
      ? process.env.OPENCLAW_GATEWAY_TOKEN
      : typeof auth.token === "string"
        ? auth.token
        : null;

    gatewayTokenPresent = Boolean(token);
    if (token) {
      if (dashboardUrl) {
        dashboardTokenizedUrl = buildBootstrapUrl(dashboardUrl, token);
      }
      if (proxyDashboardUrl) {
        proxyDashboardTokenizedUrl = buildBootstrapUrl(proxyDashboardUrl, token);
      }
    }
  }

  return {
    instanceId: instance.id,
    ownerId: instance.ownerId,
    displayName: instance.displayName,
    proxyBasePath: instance.proxyBasePath,
    systemMode: usesSystemOpenclaw(instance),
    installed,
    running,
    version,
    binaryPath,
    port,
    startedAt,
    dashboardUrl,
    dashboardTokenizedUrl,
    proxyDashboardUrl,
    proxyDashboardTokenizedUrl,
    gatewayTokenPresent,
  };
}
