export class FnTokenAuthError extends Error {
  constructor(message, options = {}) {
    super(message, options.cause ? { cause: options.cause } : undefined);
    this.name = this.constructor.name;
    if (options.code) {
      this.code = options.code;
    }
    if (options.details !== undefined) {
      this.details = options.details;
    }
  }
}

export class ConfigurationError extends FnTokenAuthError {}
export class TokenFormatError extends FnTokenAuthError {}
export class PermissionApplyError extends FnTokenAuthError {}
export class ServiceDiscoveryError extends FnTokenAuthError {}
export class TransportConnectError extends FnTokenAuthError {}
export class TransportTimeoutError extends FnTokenAuthError {}
export class RpcProtocolError extends FnTokenAuthError {}
export class InvalidFnOsTokenError extends FnTokenAuthError {}
export class FnOsAuthBackendError extends FnTokenAuthError {}
export class EntryTokenProviderNotConfiguredError extends FnTokenAuthError {}
export class EntryTokenValidationError extends FnTokenAuthError {}
