function isLikelyJsonStart(source: string, index: number): boolean {
  const start = source[index];
  if (start !== "{" && start !== "[") {
    return false;
  }

  let cursor = index + 1;
  while (cursor < source.length && /\s/.test(source[cursor])) {
    cursor += 1;
  }

  if (cursor >= source.length) {
    return false;
  }

  const next = source[cursor];
  if (start === "{") {
    return next === '"' || next === "}";
  }

  return next === "{"
    || next === "["
    || next === '"'
    || next === "]"
    || next === "-"
    || /[0-9tfn]/.test(next);
}

function isLikelyConfigPathLine(line: string): boolean {
  if (!line) {
    return false;
  }

  if (!line.startsWith("/") && !line.startsWith("~")) {
    return false;
  }

  return (
    line.endsWith(".json") ||
    line.endsWith(".jsonc") ||
    line.endsWith(".json5") ||
    line.includes("/.openclaw/")
  );
}

export function parseConfigPathFromCommandOutput(stdout: string): string | null {
  const lines = stdout
    .split("\n")
    .map((line) => line.trim())
    .filter(Boolean);

  for (const line of lines) {
    if (isLikelyConfigPathLine(line)) {
      return line;
    }
  }

  return null;
}

export function parseJsonFromCommandOutput<T>(stdout: string): T {
  const trimmed = stdout.trim();
  if (!trimmed) {
    throw new Error("Command returned empty output");
  }

  try {
    return JSON.parse(trimmed) as T;
  } catch {
    // fall through and try to extract trailing JSON payload from mixed logs
  }

  for (let index = 0; index < stdout.length; index += 1) {
    if (!isLikelyJsonStart(stdout, index)) {
      continue;
    }

    const candidate = stdout.slice(index).trim();
    try {
      return JSON.parse(candidate) as T;
    } catch {
      // continue scanning; this was likely a log line like "[plugins]"
    }
  }

  throw new Error("Invalid JSON payload in command output");
}
