import { spawn } from "node:child_process";
import type { ChildProcessWithoutNullStreams, SpawnOptionsWithoutStdio } from "node:child_process";
import type { Readable } from "node:stream";

export interface CommandResult {
  stdout: string;
  stderr: string;
  exitCode: number;
}

export interface SpawnedProcess {
  child: ChildProcessWithoutNullStreams;
  exited: Promise<number>;
}

function createSpawnOptions(options?: {
  env?: Record<string, string | undefined>;
  cwd?: string;
}): SpawnOptionsWithoutStdio {
  return {
    cwd: options?.cwd,
    env: options?.env,
    stdio: ["pipe", "pipe", "pipe"],
  };
}

export function spawnCommand(
  cmd: string[],
  options?: {
    env?: Record<string, string | undefined>;
    cwd?: string;
  }
): SpawnedProcess {
  const [file, ...args] = cmd;
  const child = spawn(file, args, createSpawnOptions(options));
  const exited = new Promise<number>((resolve, reject) => {
    child.once("error", reject);
    child.once("close", (code) => {
      resolve(typeof code === "number" ? code : -1);
    });
  });

  return { child, exited };
}

export async function collectStreamText(stream: Readable | null | undefined): Promise<string> {
  if (!stream) {
    return "";
  }

  const chunks: Buffer[] = [];
  for await (const chunk of stream) {
    chunks.push(typeof chunk === "string" ? Buffer.from(chunk) : Buffer.from(chunk));
  }
  return Buffer.concat(chunks).toString("utf8");
}

export async function runCommandText(
  cmd: string[],
  options?: {
    env?: Record<string, string | undefined>;
    cwd?: string;
    timeoutMs?: number;
    stdin?: string;
  }
): Promise<CommandResult> {
  const timeoutMs = options?.timeoutMs ?? 5000;
  const { child, exited } = spawnCommand(cmd, options);
  let timeoutId: ReturnType<typeof setTimeout> | null = null;

  if (typeof options?.stdin === "string") {
    child.stdin.write(options.stdin);
  }
  child.stdin.end();

  const timeoutPromise = new Promise<never>((_, reject) => {
    timeoutId = setTimeout(() => {
      child.kill("SIGKILL");
      reject(new Error(`Command timeout after ${timeoutMs}ms: ${cmd.join(" ")}`));
    }, timeoutMs);
  });

  try {
    const [stdout, stderr, exitCode] = await Promise.race([
      Promise.all([
        collectStreamText(child.stdout),
        collectStreamText(child.stderr),
        exited,
      ]),
      timeoutPromise,
    ]);

    return {
      stdout: stdout.trim(),
      stderr: stderr.trim(),
      exitCode,
    };
  } catch (error) {
    return {
      stdout: "",
      stderr: error instanceof Error ? error.message : String(error),
      exitCode: -1,
    };
  } finally {
    if (timeoutId) {
      clearTimeout(timeoutId);
    }
  }
}
