import { spawn } from "node:child_process";
import { createWriteStream, readlinkSync } from "fs";
import type { Readable } from "node:stream";
import { IS_WINDOWS } from "./openclaw-platform";
import { fileExists, readTextFileIfExists } from "./node-fs";
import { runCommandText } from "./node-process";

export interface ProcessSnapshot {
  pid: string;
  commandLine: string | null;
  executablePath: string | null;
}

export function isPidAlive(pid: string | null): boolean {
  if (!pid) {
    return false;
  }

  const pidNumber = Number(pid);
  if (!Number.isInteger(pidNumber) || pidNumber <= 0) {
    return false;
  }

  try {
    process.kill(pidNumber, 0);
    return true;
  } catch {
    return false;
  }
}

export async function findListeningPids(port: number): Promise<string[]> {
  try {
    if (IS_WINDOWS) {
      const result = await runCommandText([
        "powershell.exe",
        "-NoProfile",
        "-Command",
        `$ids=@(Get-NetTCPConnection -State Listen -LocalPort ${port} -ErrorAction SilentlyContinue | Select-Object -ExpandProperty OwningProcess -Unique); $ids | ForEach-Object { $_ }`,
      ]);
      if (result.exitCode !== 0 || !result.stdout) {
        return [];
      }
      return result.stdout
        .split(/\r?\n/)
        .map((line) => line.trim())
        .filter(Boolean);
    }

    const result = await runCommandText(["lsof", "-ti", `TCP:${port}`, "-sTCP:LISTEN"]);
    if (result.exitCode !== 0 || !result.stdout) {
      return [];
    }
    return result.stdout
      .split(/\r?\n/)
      .map((line) => line.trim())
      .filter(Boolean);
  } catch {
    return [];
  }
}

export async function getProcessStartTime(pid: string | null): Promise<number | null> {
  if (!pid) {
    return null;
  }

  try {
    if (IS_WINDOWS) {
      const result = await runCommandText([
        "powershell.exe",
        "-NoProfile",
        "-Command",
        `$p=Get-Process -Id ${pid} -ErrorAction SilentlyContinue; if ($p) { $p.StartTime.ToUniversalTime().ToString('o') }`,
      ]);
      if (result.exitCode !== 0 || !result.stdout) {
        return null;
      }
      const ts = Date.parse(result.stdout);
      return Number.isNaN(ts) ? null : ts;
    }

    const result = await runCommandText(["ps", "-o", "lstart=", "-p", pid]);
    if (result.exitCode !== 0 || !result.stdout) {
      return null;
    }
    const ts = Date.parse(result.stdout);
    return Number.isNaN(ts) ? null : ts;
  } catch {
    return null;
  }
}

export async function describeProcess(pid: string | null): Promise<ProcessSnapshot | null> {
  if (!pid) {
    return null;
  }

  try {
    if (IS_WINDOWS) {
      const result = await runCommandText([
        "powershell.exe",
        "-NoProfile",
        "-Command",
        `$p=Get-CimInstance Win32_Process -Filter "ProcessId = ${pid}" -ErrorAction SilentlyContinue; if ($p) { [pscustomobject]@{ ProcessId=$p.ProcessId; CommandLine=$p.CommandLine; ExecutablePath=$p.ExecutablePath } | ConvertTo-Json -Compress }`,
      ]);
      if (result.exitCode !== 0 || !result.stdout) {
        return null;
      }

      const parsed = JSON.parse(result.stdout) as {
        ProcessId?: number | string;
        CommandLine?: string | null;
        ExecutablePath?: string | null;
      };
      return {
        pid: String(parsed.ProcessId ?? pid),
        commandLine: typeof parsed.CommandLine === "string" ? parsed.CommandLine : null,
        executablePath: typeof parsed.ExecutablePath === "string" ? parsed.ExecutablePath : null,
      };
    }

    let executablePath: string | null = null;
    try {
      executablePath = readlinkSync(`/proc/${pid}/exe`);
    } catch {
      executablePath = null;
    }

    const procfsPath = `/proc/${pid}/cmdline`;
    if (await fileExists(procfsPath)) {
      const raw = await readTextFileIfExists(procfsPath);
      if (!raw) {
        return executablePath
          ? {
              pid,
              commandLine: null,
              executablePath,
            }
          : null;
      }
      const commandLine = raw.replace(/\0+/g, " ").trim();
      if (commandLine) {
        return {
          pid,
          commandLine,
          executablePath,
        };
      }
    }

    const result = await runCommandText(["ps", "-o", "args=", "-p", pid]);
    if (result.exitCode !== 0 || !result.stdout) {
      return executablePath
        ? {
            pid,
            commandLine: null,
            executablePath,
          }
        : null;
    }
    return {
      pid,
      commandLine: result.stdout,
      executablePath,
    };
  } catch {
    return null;
  }
}

export function isLikelyOpenclawProcess(snapshot: ProcessSnapshot | null): boolean {
  if (!snapshot) {
    return false;
  }

  const joined = [snapshot.executablePath, snapshot.commandLine]
    .filter((value): value is string => typeof value === "string" && value.length > 0)
    .join(" ")
    .replace(/\\/g, "/");

  if (!joined) {
    return false;
  }

  const patterns = [
    /(?:^|[\s"'=\/])openclaw(?:\.cmd|\.ps1)?(?:$|[\s"'])/i,
    /\/node_modules\/\.bin\/openclaw(?:\.cmd|\.ps1)?(?:$|[\s"'])/i,
    /\/node_modules\/openclaw\//i,
  ];

  return patterns.some((pattern) => pattern.test(joined));
}

async function pipeStreamToLog(
  stream: Readable | null | undefined,
  logStream: ReturnType<typeof createWriteStream>
): Promise<void> {
  if (!stream) {
    return;
  }
  for await (const chunk of stream) {
    if (chunk && chunk.length > 0) {
      logStream.write(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk));
    }
  }
}

export function spawnDetachedToLog(
  cmd: string[],
  options: {
    env?: Record<string, string | undefined>;
    cwd?: string;
    logPath: string;
  }
) {
  const [file, ...args] = cmd;
  const proc = spawn(file, args, {
    cwd: options.cwd,
    env: options.env,
    detached: true,
    stdio: ["ignore", "pipe", "pipe"],
  });
  const logStream = createWriteStream(options.logPath, { flags: "a" });

  void Promise.all([
    pipeStreamToLog(proc.stdout, logStream),
    pipeStreamToLog(proc.stderr, logStream),
    new Promise<void>((resolve) => {
      proc.once("close", () => resolve());
      proc.once("error", () => resolve());
    }),
  ]).finally(() => {
    logStream.end();
  });

  proc.unref();
  return proc;
}
