import { Hono } from "hono";
import { streamSSE } from "hono/streaming";
import { readdirSync, statSync } from "fs";
import { join } from "path";
import { ensureDefaultInstance } from "../lib/instances";
import { fileExists, readTextSlice } from "../lib/node-fs";
import {
  SYSTEM_OPENCLAW_LOG_PATH,
  SYSTEM_OPENCLAW_RUNTIME_LOG_DIR,
} from "../lib/config";
import { shouldUseSystemOpenclaw } from "../lib/openclaw-platform";

const app = new Hono();

/** 初始加载日志时只读取文件尾部的最大字节数 */
const TAIL_READ_BYTES = 64 * 1024;

type GatewayLogSource = "managed" | "system-wrapper" | "system-runtime";

function findLatestSystemRuntimeLogPath(): string | null {
  try {
    const candidates = readdirSync(SYSTEM_OPENCLAW_RUNTIME_LOG_DIR)
      .filter((entry) => /^openclaw-\d{4}-\d{2}-\d{2}\.log$/.test(entry))
      .map((entry) => {
        const path = join(SYSTEM_OPENCLAW_RUNTIME_LOG_DIR, entry);
        return {
          path,
          mtimeMs: statSync(path).mtimeMs,
        };
      })
      .sort((a, b) => b.mtimeMs - a.mtimeMs);

    return candidates[0]?.path ?? null;
  } catch {
    return null;
  }
}

async function resolveGatewayLogPath(): Promise<{
  path: string;
  source: GatewayLogSource;
  exists: boolean;
}> {
  const instance = ensureDefaultInstance();
  const managedPath = instance.logPath;
  if (await fileExists(managedPath)) {
    return { path: managedPath, source: "managed", exists: true };
  }

  if (shouldUseSystemOpenclaw(instance.id)) {
    const sources = await Promise.all([
      (async () => {
        if (!(await fileExists(SYSTEM_OPENCLAW_LOG_PATH))) {
          return null;
        }
        return {
          path: SYSTEM_OPENCLAW_LOG_PATH,
          source: "system-wrapper" as const,
          mtimeMs: statSync(SYSTEM_OPENCLAW_LOG_PATH).mtimeMs,
        };
      })(),
      (async () => {
        const runtimePath = findLatestSystemRuntimeLogPath();
        if (!runtimePath) {
          return null;
        }
        if (!(await fileExists(runtimePath))) {
          return null;
        }
        return {
          path: runtimePath,
          source: "system-runtime" as const,
          mtimeMs: statSync(runtimePath).mtimeMs,
        };
      })(),
    ]);

    const bestSource = sources
      .filter((candidate): candidate is NonNullable<typeof candidate> => candidate !== null)
      .sort((a, b) => b.mtimeMs - a.mtimeMs)[0];

    if (bestSource) {
      return { path: bestSource.path, source: bestSource.source, exists: true };
    }
  }

  return {
    path: managedPath,
    source: "managed",
    exists: false,
  };
}

/** 从文件尾部读取最后若干行，避免读取整个文件 */
async function readTailLines(logPath: string, maxLines: number): Promise<string[]> {
  let fileSize: number;
  try {
    fileSize = statSync(logPath).size;
  } catch {
    return [];
  }

  if (fileSize === 0) {
    return [];
  }

  const readStart = Math.max(0, fileSize - TAIL_READ_BYTES);
  const chunk = await readTextSlice(logPath, readStart, fileSize);
  const lines = chunk.split("\n").filter((line) => line.trim());

  // 如果我们不是从文件头开始读的，丢弃第一行（可能不完整）
  if (readStart > 0 && lines.length > 0) {
    lines.shift();
  }

  return lines.slice(-maxLines);
}

app.get("/logs", async (c) => {
  const abortSignal = c.req.raw.signal;

  return streamSSE(c, async (stream) => {
    const instance = ensureDefaultInstance();
    const { path: logPath, source, exists } = await resolveGatewayLogPath();

    if (exists) {
      const lines = await readTailLines(logPath, 100);
      for (const line of lines) {
        if (abortSignal.aborted) return;
        await stream.writeSSE({ data: line, event: "log" });
      }
    } else {
      const systemManaged = shouldUseSystemOpenclaw(instance.id);
      const missingMessage = systemManaged
        ? `[monitor] No gateway log file found. Checked managed log ${instance.logPath}, system wrapper log ${SYSTEM_OPENCLAW_LOG_PATH}, and runtime logs under ${SYSTEM_OPENCLAW_RUNTIME_LOG_DIR}.`
        : `[monitor] No gateway log file at ${logPath} yet. Logs will appear after monitor starts the managed gateway and the file is created.`;

      await stream.writeSSE({ data: missingMessage, event: "log" });
    }

    if (source === "system-wrapper") {
      await stream.writeSSE({
        data: `[monitor] Streaming system gateway wrapper log from ${logPath}.`,
        event: "log",
      });
    } else if (source === "system-runtime") {
      await stream.writeSSE({
        data: `[monitor] Streaming system OpenClaw runtime log from ${logPath}.`,
        event: "log",
      });
    }

    let position = exists ? statSync(logPath).size : 0;
    let buffer = "";

    const heartbeat = setInterval(async () => {
      try {
        if (abortSignal.aborted) {
          clearInterval(heartbeat);
          return;
        }
        await stream.writeSSE({ data: "", event: "heartbeat" });
      } catch {
        clearInterval(heartbeat);
      }
    }, 5000);

    try {
      while (!abortSignal.aborted) {
        await new Promise((resolve) => setTimeout(resolve, 1000));

        if (abortSignal.aborted) break;

        let size = 0;
        try {
          size = statSync(logPath).size;
        } catch {
          continue;
        }

        if (size < position) {
          position = 0;
          buffer = "";
        }

        if (size === position) {
          continue;
        }

        const chunk = await readTextSlice(logPath, position, size);
        position = size;
        buffer += chunk;

        const lines = buffer.split("\n");
        buffer = lines.pop() || "";

        for (const line of lines) {
          if (abortSignal.aborted) break;
          if (line.trim()) {
            await stream.writeSSE({ data: line, event: "log" });
          }
        }
      }
    } catch {
      // Client disconnected
    } finally {
      clearInterval(heartbeat);
    }
  });
});

export default app;
