import crypto from "node:crypto";
import os from "node:os";

export function generateReqId() {
  return crypto.randomBytes(8).toString("hex");
}

export function getCurrentUid() {
  if (typeof process.getuid === "function") {
    return process.getuid() >>> 0;
  }
  return 0;
}

export function normalizeServiceType(value) {
  if (value === 1 || value === "1" || value === "TRIMSRV") {
    return "TRIMSRV";
  }
  return "TRIMAPP";
}

export function trimNullTerminatedString(buffer) {
  let end = buffer.length;
  while (end > 0 && buffer[end - 1] === 0x00) {
    end -= 1;
  }
  return buffer.subarray(0, end).toString("utf8");
}

export function createSessionSeed() {
  return BigInt(Date.now()) * 1000n;
}

export function isWindows() {
  return os.platform() === "win32";
}

export function createIpcEndpoint(name) {
  if (isWindows()) {
    const hash = crypto.createHash("md5").update(name).digest();
    const offset = hash.readUInt16LE(0) % 1000;
    return `tcp://127.0.0.1:${38000 + offset}`;
  }
  return `/tmp/${name}.sock`;
}

export function toConnectionOptions(endpoint) {
  if (typeof endpoint !== "string") {
    return endpoint;
  }

  if (endpoint.startsWith("tcp://")) {
    const url = new URL(endpoint);
    return {
      host: url.hostname,
      port: Number(url.port)
    };
  }

  return endpoint;
}
