import { MONITOR_BASE_PATH, isLikelyDevEnvironment } from "../config";

function envFlag(name: string): boolean | null {
  const value = process.env[name];
  if (value === "1" || value?.toLowerCase() === "true") {
    return true;
  }
  if (value === "0" || value?.toLowerCase() === "false") {
    return false;
  }
  return null;
}

function envNumber(name: string, fallback: number, min: number, max: number): number {
  const raw = process.env[name];
  if (raw === undefined || raw === "") {
    return fallback;
  }
  const value = Number(raw);
  if (!Number.isFinite(value) || value < min || value > max) {
    console.warn(`[auth:config] invalid ${name}="${raw}", using default ${fallback} (range ${min}-${max})`);
    return fallback;
  }
  return value;
}

function envString(name: string): string | undefined {
  const value = process.env[name];
  if (typeof value !== "string") {
    return undefined;
  }
  const trimmed = value.trim();
  return trimmed === "" ? undefined : trimmed;
}

function normalizeBypassPath(path: string): string {
  if (!path) {
    return "/";
  }
  return path.startsWith("/") ? path : `/${path}`;
}

const defaultHealthPath = `${MONITOR_BASE_PATH || ""}/api/health` || "/api/health";
const configuredBypassPaths = process.env.FN_AUTH_BYPASS_PATHS
  ? process.env.FN_AUTH_BYPASS_PATHS.split(",").map((part) => normalizeBypassPath(part.trim())).filter(Boolean)
  : [defaultHealthPath];

export const FN_AUTH_ENABLED = envFlag("FN_AUTH_ENABLED") ?? !isLikelyDevEnvironment();
export const FN_AUTH_FNOS_COOKIE_NAME =
  envString("FN_AUTH_FNOS_COOKIE_NAME") ??
  envString("FN_AUTH_COOKIE_NAME") ??
  "fnos-token";
export const FN_AUTH_COOKIE_NAME = FN_AUTH_FNOS_COOKIE_NAME;
export const FN_AUTH_ENTRY_COOKIE_NAME = envString("FN_AUTH_ENTRY_COOKIE_NAME") ?? "entry-token";
export const FN_AUTH_TIMEOUT_MS = envNumber("FN_AUTH_TIMEOUT_MS", 2000, 100, 30_000);
export const FN_AUTH_CACHE_TTL_MS = envNumber("FN_AUTH_CACHE_TTL_MS", 120_000, 0, 600_000);
export const FN_AUTH_ENTRY_TIMEOUT_MS = envNumber(
  "FN_AUTH_ENTRY_TIMEOUT_MS",
  FN_AUTH_TIMEOUT_MS,
  100,
  30_000
);
export const FN_AUTH_ENTRY_CACHE_TTL_MS = envNumber(
  "FN_AUTH_ENTRY_CACHE_TTL_MS",
  FN_AUTH_CACHE_TTL_MS,
  0,
  600_000
);
export const FN_AUTH_ENTRY_ENDPOINT = envString("FN_AUTH_ENTRY_ENDPOINT");
export const FN_AUTH_MACHINE_ID = envString("FN_AUTH_MACHINE_ID");
export const FN_AUTH_MODE: "rpc" | "sac" = (envString("FN_AUTH_MODE") as "rpc" | "sac") ?? "sac";
export const FN_AUTH_SAC_ENDPOINT = envString("FN_AUTH_SAC_ENDPOINT");
export const FN_AUTH_DEVICE_ID_PATH = envString("FN_AUTH_DEVICE_ID_PATH");
export const FN_AUTH_REQUIRE_SAME_ORIGIN =
  envFlag("FN_AUTH_REQUIRE_SAME_ORIGIN") ?? (FN_AUTH_ENABLED && !isLikelyDevEnvironment());
export const FN_AUTH_BYPASS_PATHS = configuredBypassPaths;

export function isAuthBypassedPath(pathname: string, method: string): boolean {
  if (method !== "GET" && method !== "HEAD") {
    return false;
  }
  return FN_AUTH_BYPASS_PATHS.includes(pathname);
}
