export class ExpiringCache {
  #store = new Map();
  #maxEntries;
  #cleanupInterval;
  #writesSinceCleanup = 0;

  constructor({ maxEntries = 4096, cleanupInterval = 128 } = {}) {
    this.#maxEntries = Number.isFinite(maxEntries) && maxEntries > 0 ? Math.floor(maxEntries) : 0;
    this.#cleanupInterval = Number.isFinite(cleanupInterval) && cleanupInterval > 0
      ? Math.floor(cleanupInterval)
      : 1;
  }

  get(key) {
    const item = this.#store.get(key);
    if (!item) {
      return undefined;
    }
    if (item.expiresAt <= Date.now()) {
      this.#store.delete(key);
      return undefined;
    }
    return item.value;
  }

  set(key, value, ttlMs) {
    if (this.#maxEntries === 0) {
      return;
    }

    if (this.#store.has(key)) {
      this.#store.delete(key);
    }

    this.#store.set(key, {
      value,
      expiresAt: Date.now() + ttlMs
    });

    this.#writesSinceCleanup += 1;
    if (this.#writesSinceCleanup >= this.#cleanupInterval) {
      this.#writesSinceCleanup = 0;
      this.#pruneExpired();
    }

    while (this.#store.size > this.#maxEntries) {
      this.#pruneExpired();
      if (this.#store.size <= this.#maxEntries) {
        break;
      }
      const oldestKey = this.#store.keys().next().value;
      if (oldestKey === undefined) {
        break;
      }
      this.#store.delete(oldestKey);
    }
  }

  clear() {
    this.#store.clear();
  }

  #pruneExpired() {
    const now = Date.now();
    for (const [key, item] of this.#store.entries()) {
      if (item.expiresAt <= now) {
        this.#store.delete(key);
      }
    }
  }
}

export class InflightDeduper {
  #store = new Map();

  run(key, factory) {
    if (this.#store.has(key)) {
      return this.#store.get(key);
    }

    const promise = Promise.resolve()
      .then(factory)
      .finally(() => {
        this.#store.delete(key);
      });

    this.#store.set(key, promise);
    return promise;
  }
}
