import { Hono } from "hono";
import { mkdirSync, readFileSync, rmSync } from "fs";
import type { Context } from "hono";
import { streamSSE } from "hono/streaming";
import type { Readable } from "node:stream";
import { ensureDefaultInstance, getInstance, type InstanceRecord, updateInstance } from "../lib/instances";
import { fileExists, readTextFileIfExists, writeTextFile } from "../lib/node-fs";
import { runCommandText, spawnCommand } from "../lib/node-process";
import { activeConfigPath, ensureInstanceDirectories, openclawEnv, openclawSpawnCwd, readInstanceConfig, readInstancePort, requireOpenclawBinary, resolveOpenclawBinary, usesSystemOpenclaw, writeInstanceConfig, writeInstancePort } from "../lib/openclaw-instance";
import { describeProcess, findListeningPids, isLikelyOpenclawProcess, isPidAlive, spawnDetachedToLog } from "../lib/process-control";
import { isPortListening } from "../lib/runtime-state";
import { OPENCLAW_NPM_REGISTRY, SOUL_MD_SRC } from "../lib/config";

const app = new Hono();
const SHUTDOWN_GRACE_PERIOD_MS = 15000;
const FORCE_KILL_WAIT_MS = 5000;
const STARTUP_WAIT_MS = 30000;
const COUNTDOWN_TICK_MS = 1000;
const MAX_INSTALL_QUEUE_SIZE = 1000;

function sseData(event: string, payload: Record<string, unknown>): string {
  return JSON.stringify({ event, ...payload });
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function emitLog(
  enqueue: (data: string) => void,
  type: "stdout" | "stderr" | "info" | "success" | "error",
  line: string
): void {
  enqueue(sseData("log", { type, line }));
}

function emitState(
  enqueue: (data: string) => void,
  phase: string,
  label: string,
  extra?: Record<string, unknown>
): void {
  enqueue(sseData("state", { phase, label, ...(extra || {}) }));
}

async function readLines(
  stream: Readable | null | undefined,
  type: "stdout" | "stderr",
  onLine: (data: string) => void
) {
  let buffer = "";

  try {
    for await (const chunk of stream || []) {
      buffer += typeof chunk === "string" ? chunk : Buffer.from(chunk).toString("utf8");

      const lines = buffer.split("\n");
      buffer = lines.pop() || "";

      for (const line of lines) {
        if (line.length > 0) {
          onLine(sseData("log", { type, line }));
        }
      }
    }
    if (buffer.length > 0) {
      onLine(sseData("log", { type, line: buffer }));
    }
  } finally {}
}

function randomPort(): number {
  return Math.floor(Math.random() * 40000) + 10000;
}

async function deploySoulMd(
  instance: InstanceRecord,
  enqueue: (data: string) => void
): Promise<void> {
  if (!SOUL_MD_SRC) {
    return;
  }

  try {
    const content = await readTextFileIfExists(SOUL_MD_SRC);
    if (!content) {
      return;
    }

    const workspaceDest = `${instance.workspaceDir}/SOUL.md`;
    mkdirSync(instance.workspaceDir, { recursive: true });
    await writeTextFile(workspaceDest, content);
    emitLog(enqueue, "info", `Deployed SOUL.md to workspace ${workspaceDest}`);

    const legacyDest = `${instance.homeDir}/.openclaw/SOUL.md`;
    try {
      mkdirSync(`${instance.homeDir}/.openclaw`, { recursive: true });
      await writeTextFile(legacyDest, content);
      emitLog(enqueue, "info", `Mirrored SOUL.md to legacy path ${legacyDest}`);
    } catch (error) {
      const msg = error instanceof Error ? error.message : String(error);
      emitLog(enqueue, "stderr", `Failed to mirror SOUL.md to legacy path: ${msg}`);
    }
  } catch (error) {
    const msg = error instanceof Error ? error.message : String(error);
    emitLog(enqueue, "stderr", `Failed to deploy SOUL.md: ${msg}`);
  }
}

async function ensureOpenclawConfig(
  instance: InstanceRecord,
  port: number,
  enqueue: (data: string) => void,
  c: Context
): Promise<void> {
  await ensureInstanceDirectories(instance);

  const config = await readInstanceConfig(instance);
  const gateway = (config.gateway as Record<string, unknown>) || {};
  gateway.mode = "local";
  gateway.port = port;
  gateway.bind = "loopback";
  gateway.trustedProxies = ["127.0.0.1", "::1"];

  const auth = (gateway.auth as Record<string, unknown>) || {};
  if (typeof auth.token !== "string" || auth.token.length === 0) {
    auth.token = crypto.randomUUID().replace(/-/g, "");
  }
  gateway.auth = auth;

  const controlUi = (gateway.controlUi as Record<string, unknown>) || {};
  controlUi.enabled = true;
  controlUi.basePath = instance.proxyBasePath;
  controlUi.allowInsecureAuth = true;
  controlUi.dangerouslyDisableDeviceAuth = true;
  // Gateway is bound to loopback and only accessible through monitor proxy
  // Monitor handles all access control, so Gateway can trust all origins
  controlUi.allowedOrigins = ["*"];
  gateway.controlUi = controlUi;

  const agents = (config.agents as Record<string, unknown>) || {};
  const defaults = (agents.defaults as Record<string, unknown>) || {};
  defaults.workspace = instance.workspaceDir;
  agents.defaults = defaults;

  config.gateway = gateway;
  config.agents = agents;

  await writeInstanceConfig(instance, config);
  enqueue(
    sseData("log", {
      type: "info",
      line: `Config written: ${activeConfigPath(instance)}`,
    })
  );
  enqueue(
    sseData("log", {
      type: "info",
      line: `[gateway] seeded gateway.controlUi.allowedOrigins ${JSON.stringify(controlUi.allowedOrigins)}`,
    })
  );
}

async function listGatewayPids(instance: InstanceRecord, port: number | null): Promise<Set<string>> {
  const pids = new Set<string>();

  if (port) {
    for (const pid of await findListeningPids(port)) {
      if (pid) {
        pids.add(pid);
      }
    }
  }

  try {
    const pidFromFile = readFileSync(instance.pidPath, "utf8").trim();
    if (pidFromFile) {
      pids.add(pidFromFile);
    }
  } catch {
    // ignore missing pid file
  }

  return pids;
}

async function filterValidatedGatewayPids(
  pids: Iterable<string>,
  enqueue: (data: string) => void,
  warnedPids?: Set<string>
): Promise<Set<string>> {
  const validated = new Set<string>();

  for (const pid of pids) {
    const snapshot = await describeProcess(pid);
    if (isLikelyOpenclawProcess(snapshot)) {
      validated.add(pid);
      continue;
    }

    const detail = snapshot?.commandLine || snapshot?.executablePath || "unknown process";
    if (!warnedPids || !warnedPids.has(pid)) {
      warnedPids?.add(pid);
      emitLog(enqueue, "error", `Refusing to signal PID ${pid} because it is not recognized as an OpenClaw process: ${detail}`);
    }
  }

  return validated;
}

function fallbackGatewayPids(
  pids: Iterable<string>,
  enqueue: (data: string) => void,
  context: string
): Set<string> {
  const fallback = new Set<string>();

  for (const pid of pids) {
    if (pid === String(process.pid)) {
      emitLog(enqueue, "error", `Refusing fallback stop for PID ${pid} because it matches the monitor process itself.`);
      continue;
    }
    fallback.add(pid);
  }

  if (fallback.size > 0) {
    emitLog(
      enqueue,
      "info",
      `Falling back to configured-port PID ownership for ${context}: ${Array.from(fallback).join(", ")}`
    );
  }

  return fallback;
}

async function waitForGatewayState(
  predicate: () => Promise<boolean>,
  options: {
    timeoutMs: number;
    phase: string;
    label: string;
    enqueue: (data: string) => void;
  }
): Promise<boolean> {
  const deadline = Date.now() + options.timeoutMs;
  let lastCountdown: number | null = null;

  while (true) {
    if (await predicate()) {
      emitState(options.enqueue, options.phase, options.label, {
        countdownSeconds: 0,
        countdownTotalSeconds: Math.ceil(options.timeoutMs / 1000),
      });
      return true;
    }

    const remainingMs = deadline - Date.now();
    if (remainingMs <= 0) {
      return false;
    }

    const countdownSeconds = Math.ceil(remainingMs / 1000);
    if (countdownSeconds !== lastCountdown) {
      lastCountdown = countdownSeconds;
      emitState(options.enqueue, options.phase, options.label, {
        countdownSeconds,
        countdownTotalSeconds: Math.ceil(options.timeoutMs / 1000),
      });
    }

    await sleep(Math.min(COUNTDOWN_TICK_MS, remainingMs));
  }
}

async function gracefulStopGateway(
  instance: InstanceRecord,
  enqueue: (data: string) => void,
  reason: "stop" | "restart" | "reinstall"
): Promise<boolean> {
  const existingPort = await readInstancePort(instance);
  const warnedPids = new Set<string>();
  const initialPidCandidates = await listGatewayPids(instance, existingPort);
  let initialPids = await filterValidatedGatewayPids(initialPidCandidates, enqueue, warnedPids);
  const initiallyListening = existingPort ? await isPortListening(existingPort) : false;

  if (initialPidCandidates.size === 0 && !initiallyListening) {
    updateInstance(instance.id, { status: "stopped" });
    try {
      rmSync(instance.pidPath, { force: true });
    } catch {
      // ignore pid cleanup failures
    }
    emitState(enqueue, "stopped", `${instance.displayName} 已停止`, {
      countdownSeconds: 0,
      countdownTotalSeconds: Math.ceil(SHUTDOWN_GRACE_PERIOD_MS / 1000),
    });
    emitLog(
      enqueue,
      "info",
      existingPort
        ? `No running gateway process found on port ${existingPort}. Marked instance as stopped.`
        : "No running gateway process found. Marked instance as stopped."
    );
    return false;
  }

  if (initialPids.size === 0) {
    initialPids = fallbackGatewayPids(
      initialPidCandidates,
      enqueue,
      existingPort
        ? `${instance.displayName} on configured port ${existingPort}`
        : instance.displayName
    );
  }

  if (initialPids.size === 0) {
    throw new Error(
      existingPort
        ? `Refusing to stop ${instance.displayName}: no validated OpenClaw process found for configured port ${existingPort}, and no safe fallback PID was available.`
        : `Refusing to stop ${instance.displayName}: no validated OpenClaw process found.`
    );
  }

  const verb = reason === "stop" ? "关闭" : "重启前关闭";
  emitState(enqueue, "stopping", `正在优雅${verb} ${instance.displayName}`, {
    countdownSeconds: Math.ceil(SHUTDOWN_GRACE_PERIOD_MS / 1000),
    countdownTotalSeconds: Math.ceil(SHUTDOWN_GRACE_PERIOD_MS / 1000),
  });
  emitLog(
    enqueue,
    "info",
    `Sending SIGTERM to gateway (PID: ${Array.from(initialPids).join(", ") || "unknown"}${existingPort ? `, port: ${existingPort}` : ""})`
  );

  for (const pid of initialPids) {
    const pidNumber = Number(pid);
    if (Number.isInteger(pidNumber) && pidNumber > 0) {
      try {
        process.kill(pidNumber, "SIGTERM");
      } catch {
        // ignore already-dead pids
      }
    }
  }

  const stoppedGracefully = await waitForGatewayState(
    async () => {
      const activePids = await filterValidatedGatewayPids(await listGatewayPids(instance, existingPort), enqueue, warnedPids);
      const pidAlive = Array.from(activePids).some((pid) => isPidAlive(pid));
      const portBusy = existingPort ? await isPortListening(existingPort) : false;
      return !pidAlive && !portBusy;
    },
    {
      timeoutMs: SHUTDOWN_GRACE_PERIOD_MS,
      phase: "stopping",
      label: `等待 ${instance.displayName} 完成优雅关闭`,
      enqueue,
    }
  );

  if (!stoppedGracefully) {
    const forceKillCandidates = await listGatewayPids(instance, existingPort);
    let forceKillPids = await filterValidatedGatewayPids(forceKillCandidates, enqueue, warnedPids);
    if (forceKillPids.size === 0) {
      forceKillPids = fallbackGatewayPids(
        forceKillCandidates,
        enqueue,
        existingPort
          ? `${instance.displayName} on configured port ${existingPort} during forced stop`
          : `${instance.displayName} during forced stop`
      );
    }
    emitState(enqueue, "forcing-stop", `${instance.displayName} 优雅关闭超时，开始强制结束`, {
      countdownSeconds: Math.ceil(FORCE_KILL_WAIT_MS / 1000),
      countdownTotalSeconds: Math.ceil(FORCE_KILL_WAIT_MS / 1000),
    });
    emitLog(
      enqueue,
      "error",
      `Graceful shutdown timed out after ${Math.ceil(SHUTDOWN_GRACE_PERIOD_MS / 1000)}s. Forcing termination.`
    );

    for (const pid of forceKillPids) {
      const pidNumber = Number(pid);
      if (Number.isInteger(pidNumber) && pidNumber > 0) {
        try {
          process.kill(pidNumber, "SIGKILL");
        } catch {
          // ignore already-dead pids
        }
      }
    }

    const killed = await waitForGatewayState(
      async () => {
        const activePids = await filterValidatedGatewayPids(await listGatewayPids(instance, existingPort), enqueue, warnedPids);
        const pidAlive = Array.from(activePids).some((pid) => isPidAlive(pid));
        const portBusy = existingPort ? await isPortListening(existingPort) : false;
        return !pidAlive && !portBusy;
      },
      {
        timeoutMs: FORCE_KILL_WAIT_MS,
        phase: "forcing-stop",
        label: `等待 ${instance.displayName} 完成强制关闭`,
        enqueue,
      }
    );

    if (!killed) {
      updateInstance(instance.id, { status: "error" });
      throw new Error(
        `${instance.displayName} did not exit after graceful shutdown timeout and forced termination.`
      );
    }
  }

  updateInstance(instance.id, { status: "stopped" });
  try {
    rmSync(instance.pidPath, { force: true });
  } catch {
    // ignore pid cleanup failures
  }

  emitState(enqueue, "stopped", `${instance.displayName} 已停止`, {
    countdownSeconds: 0,
    countdownTotalSeconds: Math.ceil(SHUTDOWN_GRACE_PERIOD_MS / 1000),
  });
  emitLog(enqueue, "success", `Gateway stopped cleanly${existingPort ? ` on port ${existingPort}` : ""}.`);
  return true;
}

async function startOpenclaw(
  instance: InstanceRecord,
  port: number,
  enqueue: (data: string) => void,
  c: Context
): Promise<void> {
  await ensureOpenclawConfig(instance, port, enqueue, c);
  const openclawBinary = await requireOpenclawBinary(instance);

  const cmd = [
    openclawBinary,
    "gateway",
    "run",
    "--port",
    String(port),
    "--bind",
    "loopback",
  ];

  emitState(enqueue, "starting", `正在启动 ${instance.displayName}`, {
    countdownSeconds: Math.ceil(STARTUP_WAIT_MS / 1000),
    countdownTotalSeconds: Math.ceil(STARTUP_WAIT_MS / 1000),
  });
  emitLog(enqueue, "info", `Starting gateway: ${cmd.join(" ")}`);

  const proc = spawnDetachedToLog(cmd, {
    env: openclawEnv(instance),
    cwd: openclawSpawnCwd(instance),
    logPath: instance.logPath,
  });
  await writeTextFile(instance.pidPath, `${proc.pid}\n`);

  const listening = await waitForGatewayState(
    async () => isPortListening(port),
    {
      timeoutMs: STARTUP_WAIT_MS,
      phase: "starting",
      label: `等待 ${instance.displayName} 就绪`,
      enqueue,
    }
  );

  if (!listening) {
    const content = await readTextFileIfExists(instance.logPath);
    if (content) {
      for (const line of content.split("\n").slice(-15)) {
        if (line.trim()) {
          emitLog(enqueue, "stderr", line);
        }
      }
    }
    updateInstance(instance.id, { status: "error" });
    throw new Error(`Gateway did not start on port ${port}. See gateway logs for details.`);
  }

  updateInstance(instance.id, { gatewayPort: port, status: "running" });
  emitState(enqueue, "running", `${instance.displayName} 已就绪`, {
    countdownSeconds: 0,
    countdownTotalSeconds: Math.ceil(STARTUP_WAIT_MS / 1000),
  });
  emitLog(enqueue, "success", `openclaw gateway is running on port ${port}`);
}

async function getVersion(instance: InstanceRecord): Promise<string | null> {
  try {
    const binaryPath = await requireOpenclawBinary(instance);
    const result = await runCommandText([binaryPath, "--version"], {
      env: openclawEnv(instance),
      cwd: openclawSpawnCwd(instance),
    });
    const version = result.stdout.trim();
    return version || null;
  } catch {
    return null;
  }
}

async function hasOpenclawBinary(instance: InstanceRecord): Promise<boolean> {
  return (await resolveOpenclawBinary(instance)) !== null;
}

function resolveInstance(instanceId?: string): InstanceRecord | null {
  if (!instanceId) {
    return ensureDefaultInstance();
  }
  return getInstance(instanceId);
}

app.post("/", async (c) => {
  const body: { method?: string; action?: string; instanceId?: string } = await c.req
    .json<{ method?: string; action?: string; instanceId?: string }>()
    .catch(() => ({} as { method?: string; action?: string; instanceId?: string }));
  const method = body.method || "npm";
  const action = body.action || "install";
  const instance = resolveInstance(body.instanceId);

  if (!instance) {
    return c.json({ message: "Instance not found" }, 404);
  }

  return streamSSE(c, async (stream) => {
    const queue: string[] = [];
    let streamClosed = false;
    let writeChain = Promise.resolve();

    function enqueue(data: string) {
      if (queue.length >= MAX_INSTALL_QUEUE_SIZE) {
        console.warn(`[install] Queue size limit reached (${MAX_INSTALL_QUEUE_SIZE}), dropping message`);
        return;
      }
      queue.push(data);
      scheduleFlush();
    }

    function scheduleFlush(): void {
      writeChain = writeChain
        .then(async () => {
          if (streamClosed) {
            return;
          }
          await flushQueue();
        })
        .catch((error) => {
          streamClosed = true;
          console.error("[install] Failed to flush SSE queue:", error);
        });
    }

    async function flushQueue() {
      while (queue.length > 0) {
        const data = queue.shift()!;
        try {
          await stream.writeSSE({ data, event: "message" });
        } catch (error) {
          streamClosed = true;
          console.error("[install] Failed to write SSE:", error);
          break;
        }
      }
    }

    const heartbeat = setInterval(() => {
      if (streamClosed || queue.length > 0) {
        return;
      }
      writeChain = writeChain
        .then(async () => {
          if (!streamClosed) {
            await stream.writeSSE({ data: "", event: "heartbeat" });
          }
        })
        .catch((error) => {
          streamClosed = true;
          console.error("[install] SSE heartbeat failed:", error);
        });
    }, 5000);

    try {
      if (action === "start" || action === "restart") {
        emitLog(
          enqueue,
          "info",
          action === "restart" ? `Restarting ${instance.displayName}...` : `Starting ${instance.displayName}...`
        );

        if (!(await hasOpenclawBinary(instance))) {
          enqueue(
            sseData("error", {
              message: "openclaw binary not found. Please install first.",
            })
          );
          await writeChain;
          return;
        }

        if (action === "restart") {
          await gracefulStopGateway(instance, enqueue, "restart");
        }

        let port = await readInstancePort(instance);
        if (!port) {
          port = randomPort();
          await writeInstancePort(instance, port);
        }

        await startOpenclaw(instance, port, enqueue, c);
        const version = await getVersion(instance);
        enqueue(sseData("complete", { success: true, version, port, instanceId: instance.id }));
        await writeChain;
        return;
      }

      if (action === "stop") {
        if (usesSystemOpenclaw(instance)) {
          enqueue(
            sseData("error", {
              message: "System OpenClaw mode is attached to your existing gateway. Stop is disabled in monitor to avoid terminating the shared transparent gateway. Stop it manually if you really intend to shut it down.",
            })
          );
          await writeChain;
          return;
        }

        emitLog(enqueue, "info", `Stopping ${instance.displayName}...`);
        await gracefulStopGateway(instance, enqueue, "stop");
        enqueue(sseData("complete", { success: true, stopped: true, instanceId: instance.id }));
        await writeChain;
        return;
      }

      if (action === "reinstall") {
        if (usesSystemOpenclaw(instance)) {
          enqueue(
            sseData("log", {
              type: "info",
              line: `System OpenClaw mode detected. Skipping local reinstall and restarting the system gateway instead.`,
            })
          );

          await gracefulStopGateway(instance, enqueue, "reinstall");

          let port = await readInstancePort(instance);
          if (!port) {
            port = randomPort();
            await writeInstancePort(instance, port);
          }

          await startOpenclaw(instance, port, enqueue, c);
          const version = await getVersion(instance);
          enqueue(sseData("complete", { success: true, version, port, instanceId: instance.id }));
          await writeChain;
          return;
        }

        enqueue(
          sseData("log", {
            type: "info",
            line: `Checking updates for ${instance.displayName} and upgrading managed installation in place...`,
          })
        );

        await gracefulStopGateway(instance, enqueue, "reinstall");
      }

      enqueue(
        sseData("log", {
          type: "info",
          line: `Starting installation with method: ${method}`,
        })
      );

      if (usesSystemOpenclaw(instance)) {
        enqueue(
          sseData("log", {
            type: "info",
            line: `System OpenClaw mode detected. Monitor will use the existing OpenClaw installation and ~/.openclaw config instead of creating a managed local install.`,
          })
        );

        if (!(await hasOpenclawBinary(instance))) {
          enqueue(
            sseData("error", {
              message: "System OpenClaw binary not found. Install OpenClaw globally first, then use Start/Restart from monitor.",
            })
          );
          await writeChain;
          return;
        }

        let port = await readInstancePort(instance);
        if (!port) {
          port = randomPort();
          await writeInstancePort(instance, port);
        }

        await startOpenclaw(instance, port, enqueue, c);
        const version = await getVersion(instance);
        enqueue(sseData("complete", { success: true, version, port, instanceId: instance.id }));
        await writeChain;
        return;
      }

      const npmCacheDir = `${instance.installDir}/.npm-cache`;
      const env: Record<string, string | undefined> = {
        ...process.env,
        SHARP_IGNORE_GLOBAL_LIBVIPS: "1",
        HOME: instance.homeDir,
        npm_config_cache: npmCacheDir,
      };

      await ensureInstanceDirectories(instance);
      mkdirSync(npmCacheDir, { recursive: true });

      const packageJsonPath = `${instance.installDir}/package.json`;
      if (!(await fileExists(packageJsonPath))) {
        await writeTextFile(packageJsonPath, JSON.stringify({
          name: "managed-openclaw",
          private: true,
        }, null, 2));
      }

      let cmd: string[];
      if (method === "npm") {
        cmd = [
          "npm",
          "install",
          "--prefix",
          instance.installDir,
          "--registry",
          OPENCLAW_NPM_REGISTRY,
          "openclaw@latest",
        ];
        enqueue(
          sseData("log", {
            type: "info",
            line: `Install target: ${instance.installDir}`,
          })
        );
        enqueue(
          sseData("log", {
            type: "info",
            line: `Using package registry: ${OPENCLAW_NPM_REGISTRY}`,
          })
        );
      } else {
        cmd = [
          "bash",
          "-c",
          "curl -fsSL https://openclaw.ai/install.sh | bash",
        ];
      }

      enqueue(
        sseData("log", { type: "info", line: `Running: ${cmd.join(" ")}` })
      );

      const { child, exited } = spawnCommand(cmd, {
        env,
        cwd: instance.installDir,
      });

      const stdoutDone = readLines(child.stdout, "stdout", enqueue);
      const stderrDone = readLines(child.stderr, "stderr", enqueue);

      await Promise.all([stdoutDone, stderrDone]);
      const exitCode = await exited;
      await writeChain;

      if (exitCode === 0) {
        enqueue(
          sseData("log", {
            type: "success",
            line: "npm install completed successfully!",
          })
        );

        await deploySoulMd(instance, enqueue);

        let port = await readInstancePort(instance);
        if (!port) {
          port = randomPort();
          await writeInstancePort(instance, port);
          enqueue(
            sseData("log", {
              type: "info",
              line: `Assigned openclaw port: ${port}`,
            })
          );
        } else {
          enqueue(
            sseData("log", {
              type: "info",
              line: `Reusing configured openclaw port: ${port}`,
            })
          );
        }

        await startOpenclaw(instance, port, enqueue, c);
        const version = await getVersion(instance);
        enqueue(sseData("complete", { success: true, version, port, instanceId: instance.id }));
      } else {
        updateInstance(instance.id, { status: "install_failed" });
        enqueue(
          sseData("error", {
            message: `Installation failed with exit code ${exitCode}`,
            exitCode,
          })
        );
      }
    } catch (e: unknown) {
      const message = e instanceof Error ? e.message : String(e);
      enqueue(sseData("error", { message }));
    } finally {
      clearInterval(heartbeat);
      await writeChain;
      await flushQueue();
      streamClosed = true;
    }
  });
});

export default app;
