import { fileExists, readTextFile } from "./node-fs";

function stripJsonComments(text: string): string {
  let result = "";
  let index = 0;
  let inSingleQuote = false;
  let inDoubleQuote = false;

  while (index < text.length) {
    const char = text[index];
    const next = text[index + 1];
    const previous = text[index - 1];

    if (!inDoubleQuote && char === "'" && previous !== "\\") {
      inSingleQuote = !inSingleQuote;
      result += char;
      index += 1;
      continue;
    }

    if (!inSingleQuote && char === '"' && previous !== "\\") {
      inDoubleQuote = !inDoubleQuote;
      result += char;
      index += 1;
      continue;
    }

    if (!inSingleQuote && !inDoubleQuote && char === "/" && next === "/") {
      index += 2;
      while (index < text.length && text[index] !== "\n") {
        index += 1;
      }
      continue;
    }

    if (!inSingleQuote && !inDoubleQuote && char === "/" && next === "*") {
      index += 2;
      while (index < text.length && !(text[index] === "*" && text[index + 1] === "/")) {
        index += 1;
      }
      index += 2;
      continue;
    }

    result += char;
    index += 1;
  }

  return result;
}

function normalizeConfigTextToJson(text: string): string {
  return stripJsonComments(text)
    .replace(/^\uFEFF/, "")
    .replace(/([{,]\s*)([A-Za-z_$][\w$-]*)(\s*:)/g, '$1"$2"$3')
    .replace(/'([^'\\]*(?:\\.[^'\\]*)*)'/g, (_, value: string) => {
      const normalized = value
        .replace(/\\/g, "\\\\")
        .replace(/"/g, '\\"');
      return `"${normalized}"`;
    })
    .replace(/,\s*([}\]])/g, "$1");
}

export function parseLooseConfig(text: string): Record<string, unknown> {
  const trimmed = text.trim();
  if (!trimmed) {
    return {};
  }

  try {
    return JSON.parse(trimmed) as Record<string, unknown>;
  } catch {
    return JSON.parse(normalizeConfigTextToJson(trimmed)) as Record<string, unknown>;
  }
}

export async function readLooseConfigFile(path: string): Promise<Record<string, unknown>> {
  try {
    if (!(await fileExists(path))) {
      return {};
    }

    return parseLooseConfig(await readTextFile(path));
  } catch {
    return {};
  }
}
