const MODEL_CATALOG_CACHE_TTL_MS = 5 * 60 * 1000;

type ProviderType = "builtin" | "custom-openai" | "ollama";
type ProviderEditorSupport = "full" | "cli-only";

export interface BuiltinProviderPreset {
  providerId: string;
  baseUrl: string;
  api?: string;
  authHeader?: boolean;
}

export interface ProviderCapability {
  providerId: string;
  displayName: string;
  providerType: ProviderType;
  editorSupport: ProviderEditorSupport;
  editorReason?: string;
  baseUrl?: string;
  api?: string;
  authHeader?: boolean;
}

interface OpenClawConfigProviderModel {
  id: string;
  name?: string;
}

interface OpenClawConfigProvider {
  api?: string;
  apiKey?: string;
  baseUrl?: string;
  models?: OpenClawConfigProviderModel[];
  [key: string]: unknown;
}

interface CatalogItem {
  key: string;
  name: string;
  input?: string;
  contextWindow?: number;
  local?: boolean;
  available?: boolean;
  missing?: boolean;
  providerId: string;
  providerType: ProviderType;
  modelId: string;
}

interface CatalogResponse {
  count: number;
  models: CatalogItem[];
  providerPresets: BuiltinProviderPreset[];
  providerCapabilities: ProviderCapability[];
}

interface ModelsStatusResponse {
  configPath: string;
  defaultModel: string | null;
  resolvedDefault?: string | null;
  fallbacks?: string[];
  imageModel?: string | null;
  imageFallbacks?: string[];
}

interface ConfigValidationResponse {
  valid: boolean;
  path: string;
  error?: string;
  errors?: string[];
}

const MODELS_CATALOG_COMMAND_TIMEOUT_MS = 30_000;
const MODELS_CONFIG_VALIDATE_TIMEOUT_MS = 10_000;

