function humanizeProviderId(providerId: string): string {
  return providerId
    .split(/[-_]/)
    .filter(Boolean)
    .map((segment) => {
      const lower = segment.toLowerCase();
      if (lower === "ai") {
        return "AI";
      }
      if (lower === "cn") {
        return "CN";
      }
      return segment.charAt(0).toUpperCase() + segment.slice(1);
    })
    .join(" ");
}

function providerDisplayName(providerId: string): string {
  return PROVIDER_LABELS[providerId] || humanizeProviderId(providerId);
}

function editorSupportForProvider(
  providerId: string,
  providerType: ProviderType
): { editorSupport: ProviderEditorSupport; editorReason?: string } {
  if (providerType === "custom-openai" || providerType === "ollama") {
    return { editorSupport: "full" };
  }

  if (getBuiltinProviderPreset(providerId)) {
    return { editorSupport: "full" };
  }

  return {
    editorSupport: "cli-only",
    editorReason: "这个内建 provider 来自较新的 OpenClaw 能力或专用 onboarding，monitor 暂未确认它的完整可视化 schema。",
  };
}

function getBuiltinProviderPreset(providerId: string): BuiltinProviderPreset | null {
  const preset = BUILTIN_PROVIDER_PRESETS[providerId];
  if (!preset) {
    return null;
  }

  return {
    providerId,
    ...preset,
  };
}

function listBuiltinProviderPresets(): BuiltinProviderPreset[] {
  return Object.entries(BUILTIN_PROVIDER_PRESETS).map(([providerId, preset]) => ({
    providerId,
    ...preset,
  }));
}

function asObject(value: unknown): Record<string, unknown> {
  return value && typeof value === "object" && !Array.isArray(value)
    ? (value as Record<string, unknown>)
    : {};
}

async function readConfigFile(path: string): Promise<Record<string, unknown>> {
  return readLooseConfigFile(path);
}

function splitModelRef(modelRef: string): { providerId: string; modelId: string } {
  const [providerId, ...rest] = modelRef.split("/");
  return {
    providerId,
    modelId: rest.join("/"),
  };
}

function catalogModelName(catalogMap: Map<string, CatalogItem>, modelRef: string): string {
  return catalogMap.get(modelRef)?.name || splitModelRef(modelRef).modelId;
}

function inferredProviderType(providerId: string, providerConfig: OpenClawConfigProvider | null): ProviderType {
  if (getBuiltinProviderPreset(providerId)) {
    return providerId === "ollama" ? "ollama" : "builtin";
  }
  if (providerId === "ollama" || providerConfig?.api === "ollama") {
    return "ollama";
  }
  if (providerConfig?.baseUrl) {
    return "custom-openai";
  }
  return "builtin";
}

async function resolveOpenclawBinary(instance: InstanceRecord): Promise<string> {
  return requireOpenclawBinary(instance);
}

async function tryResolveOpenclawBinary(instance: InstanceRecord): Promise<string | null> {
  return maybeResolveOpenclawBinary(instance);
}

async function runOpenclawCommand(
  instance: InstanceRecord,
  args: string[],
  options?: { stdin?: string; timeoutMs?: number }
): Promise<{ stdout: string; stderr: string; exitCode: number }> {
  const bin = await resolveOpenclawBinary(instance);
  return runCommandText([bin, ...args], {
    stdin: options?.stdin,
    timeoutMs: options?.timeoutMs,
    env: openclawEnv(instance),
    cwd: openclawSpawnCwd(instance),
  });
}

async function runOpenclawJsonCommand<T>(
  instance: InstanceRecord,
  args: string[],
  options?: { timeoutMs?: number }
): Promise<T> {
  const result = await runOpenclawCommand(instance, args, options);
  if (result.exitCode !== 0) {
    throw new Error(result.stderr || result.stdout || `openclaw ${args.join(" ")} failed`);
  }

  try {
    return parseJsonFromCommandOutput<T>(result.stdout);
  } catch {
    throw new Error(`Invalid JSON from openclaw ${args.join(" ")}`);
  }
}

async function runOpenclawJsonCommandWithTimeout<T>(
  instance: InstanceRecord,
  args: string[],
  timeoutMs: number
): Promise<T> {
  const commandPromise = runOpenclawJsonCommand<T>(instance, args);

  if (!Number.isFinite(timeoutMs) || timeoutMs <= 0) {
    return commandPromise;
  }

  let timeoutId: ReturnType<typeof setTimeout> | null = null;

  try {
    return await Promise.race([
      commandPromise,
      new Promise<T>((_, reject) => {
        timeoutId = setTimeout(() => {
          reject(new Error(`openclaw ${args.join(" ")} timed out after ${timeoutMs}ms`));
        }, timeoutMs);
      }),
    ]);
  } finally {
    if (timeoutId) {
      clearTimeout(timeoutId);
    }
  }
}

async function getActiveConfigPath(instance: InstanceRecord): Promise<string> {
  return activeConfigPath(instance);
}

function makeJsonArg(value: unknown): string {
  return JSON.stringify(value);
}

async function setConfigValue(instance: InstanceRecord, path: string, value: unknown): Promise<void> {
  const result = await runOpenclawCommand(instance, ["config", "set", path, makeJsonArg(value), "--strict-json"]);
  if (result.exitCode !== 0) {
    throw new Error(result.stderr || result.stdout || `Failed to set ${path}`);
  }
}

async function unsetConfigValue(instance: InstanceRecord, path: string): Promise<void> {
  const result = await runOpenclawCommand(instance, ["config", "unset", path]);
  if (result.exitCode !== 0) {
    throw new Error(result.stderr || result.stdout || `Failed to unset ${path}`);
  }
}

function providerModelName(
  providerConfig: OpenClawConfigProvider | null,
  modelId: string,
  fallbackName: string
): string {
  const models = Array.isArray(providerConfig?.models) ? providerConfig.models : [];
  const matched = models.find((model) => typeof model?.id === "string" && model.id === modelId);
  return typeof matched?.name === "string" && matched.name.trim()
    ? matched.name.trim()
    : fallbackName;
}

function buildConfiguredModelEntry(
  modelRef: string,
  role: "primary" | "fallback",
  catalogMap: Map<string, CatalogItem>,
  providers: Record<string, OpenClawConfigProvider>
): ModelConfigEntry {
  const { providerId, modelId } = splitModelRef(modelRef);
  const providerConfig = providers[providerId] || null;
  const catalogItem = catalogMap.get(modelRef);
  const providerApiKey = typeof providerConfig?.apiKey === "string"
    ? providerConfig.apiKey
    : null;

  return {
    modelRef,
    providerId,
    modelId,
    displayName: providerModelName(
      providerConfig,
      modelId,
      catalogItem?.name || modelId
    ),
    role,
    providerType: inferredProviderType(providerId, providerConfig),
    api: typeof providerConfig?.api === "string" ? providerConfig.api : null,
    baseUrl: typeof providerConfig?.baseUrl === "string" ? providerConfig.baseUrl : null,
    apiKeyConfigured: Boolean(providerApiKey),
    apiKeySource: providerApiKey ? "provider" : null,
    providerConfigured: Boolean(providerConfig),
    available: Boolean(catalogItem?.available),
    local: Boolean(catalogItem?.local),
  };
}

function buildConfiguredProviderEntry(
  providerId: string,
  providerConfig: OpenClawConfigProvider,
  catalogMap: Map<string, CatalogItem>
): ConfiguredProviderEntry {
  const providerType = inferredProviderType(providerId, providerConfig);
  const editorSupport = editorSupportForProvider(providerId, providerType);
  const providerApiKey = typeof providerConfig.apiKey === "string"
    ? providerConfig.apiKey
    : null;
  const models = Array.isArray(providerConfig.models) ? providerConfig.models : [];

  return {
    id: providerId,
    displayName: providerDisplayName(providerId),
    providerType,
    api: typeof providerConfig.api === "string" ? providerConfig.api : null,
    baseUrl: typeof providerConfig.baseUrl === "string" ? providerConfig.baseUrl : null,
    apiKeyConfigured: Boolean(providerApiKey),
    apiKeySource: providerApiKey ? "provider" : null,
    editorSupport: editorSupport.editorSupport,
    editorReason: editorSupport.editorReason,
    models: models
      .filter((model): model is OpenClawConfigProviderModel => typeof model?.id === "string" && model.id.length > 0)
      .map((model) => {
        const modelRef = `${providerId}/${model.id}`;
        const catalogItem = catalogMap.get(modelRef);
        return {
          modelRef,
          modelId: model.id,
          displayName: typeof model.name === "string" && model.name.trim()
            ? model.name.trim()
            : catalogItem?.name || model.id,
          available: Boolean(catalogItem?.available),
          local: Boolean(catalogItem?.local),
        };
      }),
  };
}

function buildProviderCapabilities(models: CatalogItem[]): ProviderCapability[] {
  const providerTypeMap = new Map<string, ProviderType>();

  for (const preset of listBuiltinProviderPresets()) {
    providerTypeMap.set(preset.providerId, preset.providerId === "ollama" ? "ollama" : "builtin");
  }

  for (const model of models) {
    if (!providerTypeMap.has(model.providerId)) {
      providerTypeMap.set(model.providerId, model.providerType);
    }
  }

  return Array.from(providerTypeMap.entries())
    .sort((a, b) => providerDisplayName(a[0]).localeCompare(providerDisplayName(b[0])))
    .map(([providerId, providerType]) => {
      const preset = getBuiltinProviderPreset(providerId);
      const editorSupport = editorSupportForProvider(providerId, providerType);

      return {
        providerId,
        displayName: providerDisplayName(providerId),
        providerType,
        editorSupport: editorSupport.editorSupport,
        editorReason: editorSupport.editorReason,
        baseUrl: preset?.baseUrl,
        api: preset?.api,
        authHeader: preset?.authHeader,
      } satisfies ProviderCapability;
    });
}

export async function getModelsCatalog(instance: InstanceRecord): Promise<CatalogResponse> {
  if (!(await tryResolveOpenclawBinary(instance))) {
    catalogCache.delete(instance.id);
    return {
      count: 0,
      models: [],
      providerPresets: listBuiltinProviderPresets(),
      providerCapabilities: buildProviderCapabilities([]),
    };
  }

  const now = Date.now();
  const cached = catalogCache.get(instance.id);
  if (cached && now - cached.fetchedAt < MODEL_CATALOG_CACHE_TTL_MS) {
    return cached.value;
  }

  const raw = await runOpenclawJsonCommand<{ count: number; models: Array<Record<string, unknown>> }>(
    instance,
    ["models", "list", "--all", "--json"],
    { timeoutMs: MODELS_CATALOG_COMMAND_TIMEOUT_MS }
  );

  const value: CatalogResponse = {
    count: typeof raw.count === "number" ? raw.count : 0,
    models: Array.isArray(raw.models)
      ? raw.models.flatMap((model) => {
          const key = typeof model.key === "string" ? model.key : "";
          if (!key.includes("/")) {
            return [];
          }
          const { providerId, modelId } = splitModelRef(key);
          const item: CatalogItem = {
            key,
            name: typeof model.name === "string" ? model.name : modelId,
            local: Boolean(model.local),
            available: Boolean(model.available),
            missing: Boolean(model.missing),
            providerId,
            providerType: inferredProviderType(providerId, null),
            modelId,
          };

          if (typeof model.input === "string") {
            item.input = model.input;
          }
          if (typeof model.contextWindow === "number") {
            item.contextWindow = model.contextWindow;
          }

          return [item];
        })
      : [],
    providerPresets: listBuiltinProviderPresets(),
    providerCapabilities: [],
  };

  value.providerCapabilities = buildProviderCapabilities(value.models);

  catalogCache.set(instance.id, {
    fetchedAt: now,
    value,
  });

  return value;
}

export async function getModelsConfig(instance: InstanceRecord): Promise<ModelsConfigResponse> {
  const binaryPath = await tryResolveOpenclawBinary(instance);
  const activeConfigPath = await getActiveConfigPath(instance);
  const configExists = existsSync(activeConfigPath);
  const config = await readConfigFile(activeConfigPath);
  let validation: ConfigValidationResponse = {
    valid: true,
    path: activeConfigPath,
  };

  if (binaryPath && configExists) {
    try {
      validation = await runOpenclawJsonCommandWithTimeout<ConfigValidationResponse>(
        instance,
        ["config", "validate", "--json"],
        MODELS_CONFIG_VALIDATE_TIMEOUT_MS
      );
    } catch (error) {
      console.warn("[models] skipped blocking config validation for config snapshot:", error);
    }
  }

  const catalogMap = new Map<string, CatalogItem>();
  const providerConfig = asObject(asObject(config.models).providers);
  const providers: Record<string, OpenClawConfigProvider> = {};

  for (const [providerId, value] of Object.entries(providerConfig)) {
    providers[providerId] = asObject(value) as OpenClawConfigProvider;
  }

  const configuredProviders = Object.entries(providers).map(([providerId, provider]) =>
    buildConfiguredProviderEntry(providerId, provider, catalogMap)
  );

  return {
    configPath: validation.path || activeConfigPath,
    configExists,
    validation: {
      valid: Boolean(validation.valid),
      message: Array.isArray(validation.errors) && validation.errors.length > 0
        ? validation.errors.join("; ")
        : typeof validation.error === "string" && validation.error.length > 0
          ? validation.error
          : undefined,
    },
    configuredProviders,
  };
}

function normalizeProviderInput(provider: ModelsProviderInput): ModelsProviderInput {
  const providerId = provider.providerId.trim();
  const api = typeof provider.api === "string" ? provider.api.trim() : undefined;
  const apiKey = typeof provider.apiKey === "string" ? provider.apiKey.trim() : provider.apiKey;
  const baseUrl = provider.baseUrl?.trim();
  const modelIds = Array.from(
    new Set(
      Array.isArray(provider.modelIds)
        ? provider.modelIds
          .map((modelId) => modelId.trim())
          .filter((modelId) => modelId.length > 0)
        : []
    )
  );

  if (!providerId) {
    throw new Error("providerId is required");
  }
  if (!["builtin", "custom-openai", "ollama"].includes(provider.providerType)) {
    throw new Error("providerType is invalid");
  }
  if (provider.providerType === "builtin" && !getBuiltinProviderPreset(providerId)) {
    throw new Error(
      `内建 provider ${providerId} 当前不在 monitor 已确认支持的可视化范围内，请改用 OpenClaw 官方 onboarding 或 CLI 管理`
    );
  }
  if (modelIds.length === 0) {
    throw new Error(`provider ${providerId} must include at least one modelId`);
  }

  return {
    providerId,
    providerType: provider.providerType,
    api,
    apiKey,
    baseUrl: baseUrl || "",
    modelIds,
  };
}

function catalogLookupMap(catalog: CatalogResponse): Map<string, CatalogItem> {
  return new Map(catalog.models.map((model) => [model.key, model]));
}

function providerModelRef(providerId: string, modelId: string): string {
  return `${providerId}/${modelId}`;
}

function providerApiForProviderInput(
  provider: ModelsProviderInput,
  currentProvider?: OpenClawConfigProvider,
  preset?: BuiltinProviderPreset | null
): string | undefined {
  if (typeof provider.api === "string" && provider.api.trim()) {
    return provider.api.trim();
  }
  if (typeof currentProvider?.api === "string" && currentProvider.api.trim()) {
    return currentProvider.api;
  }
  if (typeof preset?.api === "string" && preset.api.trim()) {
    return preset.api;
  }

  if (provider.providerType === "ollama") {
    return "ollama";
  }

  if (provider.providerType === "custom-openai") {
    return "openai-completions";
  }

  return undefined;
}

function displayNameForProviderModel(
  providerId: string,
  modelId: string,
  catalogMap: Map<string, CatalogItem>
): string {
  return catalogMap.get(providerModelRef(providerId, modelId))?.name || modelId;
}

function providerModelRefsFromProviders(
  providers: Record<string, OpenClawConfigProvider>
): Set<string> {
  const refs = new Set<string>();

  for (const [providerId, provider] of Object.entries(providers)) {
    const models = Array.isArray(provider.models) ? provider.models : [];
    for (const model of models) {
      if (typeof model?.id === "string" && model.id.trim()) {
        refs.add(providerModelRef(providerId, model.id.trim()));
      }
    }
  }

  return refs;
}

function buildSyncedAllowlist(
  currentAllowlist: Record<string, unknown>,
  currentProviders: Record<string, OpenClawConfigProvider>,
  nextProviders: Record<string, OpenClawConfigProvider>
): Record<string, Record<string, unknown>> {
  const previousProviderModelRefs = providerModelRefsFromProviders(currentProviders);
  const nextProviderModelRefs = providerModelRefsFromProviders(nextProviders);
  const nextAllowlist: Record<string, Record<string, unknown>> = {};

  for (const [modelRef, value] of Object.entries(currentAllowlist)) {
    if (previousProviderModelRefs.has(modelRef) && !nextProviderModelRefs.has(modelRef)) {
      continue;
    }
    nextAllowlist[modelRef] = asObject(value);
  }

  for (const modelRef of nextProviderModelRefs) {
    nextAllowlist[modelRef] = asObject(nextAllowlist[modelRef]);
  }

  return nextAllowlist;
}

export async function saveModelsConfig(
  instance: InstanceRecord,
  payload: SaveModelsConfigPayload
): Promise<ModelsConfigResponse> {
  console.log(`[models] saveModelsConfig start for instance=${instance.id}`);
  if (!(await tryResolveOpenclawBinary(instance))) {
    throw new Error("OpenClaw is not installed yet. Install it before configuring models.");
  }

  if (!Array.isArray(payload.providers)) {
    throw new Error("providers must be an array");
  }

  const normalizedProviders = payload.providers.map(normalizeProviderInput);
  console.log(`[models] normalized providers=${normalizedProviders.length}`);

  const uniqueProviderIds = new Set<string>();
  for (const provider of normalizedProviders) {
    if (uniqueProviderIds.has(provider.providerId)) {
      throw new Error(`Duplicate provider entry: ${provider.providerId}`);
    }
    uniqueProviderIds.add(provider.providerId);
  }

  const configPath = await getActiveConfigPath(instance);
  console.log(`[models] target config path=${configPath}`);
  const currentConfig = await readConfigFile(configPath);
  const currentProvidersRaw = asObject(asObject(currentConfig.models).providers);
  const currentDefaultsRaw = asObject(asObject(currentConfig.agents).defaults);
  const currentAllowlist = asObject(currentDefaultsRaw.models);
  const currentProviders: Record<string, OpenClawConfigProvider> = {};
  for (const [providerId, value] of Object.entries(currentProvidersRaw)) {
    currentProviders[providerId] = asObject(value) as OpenClawConfigProvider;
  }

  const catalogMap = catalogLookupMap(await getModelsCatalog(instance));
  const nextProviders: Record<string, OpenClawConfigProvider> = {};

  for (const provider of normalizedProviders) {
    const currentProvider = currentProviders[provider.providerId];
    const preset = getBuiltinProviderPreset(provider.providerId);
    const nextProvider: OpenClawConfigProvider = currentProvider
      ? { ...currentProvider }
      : {};
    const api = providerApiForProviderInput(provider, currentProvider, preset);
    const effectiveBaseUrl = provider.baseUrl
      || (typeof currentProvider?.baseUrl === "string" ? currentProvider.baseUrl.trim() : "")
      || preset?.baseUrl
      || "";

    if (!effectiveBaseUrl) {
      throw new Error(
        `provider ${provider.providerId} 缺少 baseUrl；请手动填写，或先在 monitor 内建预设中补充它`
      );
    }

    if (api) {
      nextProvider.api = api;
    }
    nextProvider.baseUrl = effectiveBaseUrl;
    if (typeof currentProvider?.authHeader === "boolean") {
      nextProvider.authHeader = currentProvider.authHeader;
    } else if (typeof preset?.authHeader === "boolean") {
      nextProvider.authHeader = preset.authHeader;
    }
    if (typeof provider.apiKey === "string") {
      if (provider.providerType === "ollama") {
        nextProvider.apiKey = provider.apiKey || "ollama-local";
      } else if (provider.apiKey) {
        nextProvider.apiKey = provider.apiKey;
      }
    } else if (typeof currentProvider?.apiKey === "string") {
      nextProvider.apiKey = currentProvider.apiKey;
    }

    nextProvider.models = provider.modelIds.map((modelId) => ({
      id: modelId,
      name: displayNameForProviderModel(provider.providerId, modelId, catalogMap),
    }));

    nextProviders[provider.providerId] = nextProvider;
  }
  const nextAllowlist = buildSyncedAllowlist(currentAllowlist, currentProviders, nextProviders);

  console.log("[models] next providers summary");
  console.log(JSON.stringify(
    Object.fromEntries(
      Object.entries(nextProviders).map(([providerId, provider]) => [
        providerId,
        {
          api: provider.api ?? null,
          baseUrl: provider.baseUrl ?? null,
          authHeader: typeof provider.authHeader === "boolean" ? provider.authHeader : null,
          apiKeyConfigured: typeof provider.apiKey === "string" && provider.apiKey.length > 0,
          modelIds: Array.isArray(provider.models)
            ? provider.models
              .filter((model): model is OpenClawConfigProviderModel => typeof model?.id === "string")
              .map((model) => model.id)
            : [],
        },
      ])
    ),
    null,
    2
  ));

  const originalSnapshot = {
    exists: await fileExists(configPath),
    text: (await readTextFileIfExists(configPath)) || "",
  };

  try {
    console.log("[models] writing models.providers");
    if (Object.keys(nextProviders).length > 0) {
      await setConfigValue(instance, "models.providers", nextProviders);
    } else {
      await unsetConfigValue(instance, "models.providers").catch(() => undefined);
    }

    if (Object.keys(nextAllowlist).length > 0) {
      console.log("[models] writing agents.defaults.models");
      await setConfigValue(instance, "agents.defaults.models", nextAllowlist);
    } else {
      console.log("[models] clearing agents.defaults.models");
      await unsetConfigValue(instance, "agents.defaults.models").catch(() => undefined);
    }

    console.log("[models] validating config");
    const validation = await runOpenclawJsonCommand<{ valid: boolean; path: string; errors?: string[] }>(
      instance,
      ["config", "validate", "--json"]
    );

    if (!validation.valid) {
      throw new Error(
        Array.isArray(validation.errors) && validation.errors.length > 0
          ? validation.errors.join("; ")
          : "Config validation failed"
      );
    }
  } catch (error) {
    console.error("[models:error] saveModelsConfig failed, rolling back config file");
    console.error(error instanceof Error ? error.stack || error.message : String(error));
    if (originalSnapshot.exists) {
      await writeTextFile(configPath, originalSnapshot.text);
    } else if (await fileExists(configPath)) {
      await rm(configPath, { force: true });
    }
    throw error;
  }

  console.log("[models] saveModelsConfig completed");
  return getModelsConfig(instance);
}
