import { accessSync, constants } from "node:fs";
import { delimiter, join } from "path";
import { DEFAULT_INSTANCE_ID, isLikelyDevEnvironment } from "./config";

export const IS_WINDOWS = process.platform === "win32";

export function managedOpenclawBinPath(installDir: string): string {
  const binName = IS_WINDOWS ? "openclaw.cmd" : "openclaw";
  return `${installDir}/node_modules/.bin/${binName}`;
}

export function prependToPath(pathValue: string | undefined, entry: string): string {
  return pathValue ? `${entry}${delimiter}${pathValue}` : entry;
}

export function resolveSystemOpenclawBinary(): string | null {
  try {
    const pathEntries = (process.env.PATH || "").split(delimiter).filter(Boolean);
    const candidates = IS_WINDOWS
      ? ["openclaw.cmd", "openclaw.exe", "openclaw.bat", "openclaw"]
      : ["openclaw"];

    for (const entry of pathEntries) {
      for (const candidate of candidates) {
        const fullPath = join(entry, candidate);
        try {
          accessSync(fullPath, IS_WINDOWS ? constants.F_OK : constants.X_OK);
          return fullPath;
        } catch {
          // ignore
        }
      }
    }
    return null;
  } catch {
    return null;
  }
}

export function shouldUseSystemOpenclaw(instanceId: string): boolean {
  if (instanceId !== DEFAULT_INSTANCE_ID) {
    return false;
  }

  if (process.env.OPENCLAW_USE_SYSTEM_CONFIG === "1") {
    return true;
  }

  if (process.env.OPENCLAW_USE_SYSTEM_CONFIG === "0") {
    return false;
  }

  const systemBinary = resolveSystemOpenclawBinary();
  if (!systemBinary) {
    return false;
  }

  if (process.platform === "darwin" || process.platform === "win32") {
    return isLikelyDevEnvironment();
  }

  return false;
}
