import type { FnOsIdentity, FnTokenAuthClient, SacTokenAuthClient } from "./types";
import { createFnTokenAuth, createSacTokenAuth } from "fn-token-auth";
import {
  FN_AUTH_CACHE_TTL_MS,
  FN_AUTH_DEVICE_ID_PATH,
  FN_AUTH_ENTRY_CACHE_TTL_MS,
  FN_AUTH_ENTRY_ENDPOINT,
  FN_AUTH_ENTRY_TIMEOUT_MS,
  FN_AUTH_MACHINE_ID,
  FN_AUTH_MODE,
  FN_AUTH_SAC_ENDPOINT,
  FN_AUTH_TIMEOUT_MS,
} from "./config";

const NON_RETRYABLE_ERROR_NAMES = new Set([
  "InvalidFnOsTokenError",
  "TokenFormatError",
  "ConfigurationError",
  "EntryTokenProviderNotConfiguredError",
]);

const MAX_RETRIES = 1;
const RETRY_DELAY_MS = 150;

type AuthClient = FnTokenAuthClient | SacTokenAuthClient;

let authClient: AuthClient | null = null;
let cleanupHooksRegistered = false;

function ensureCleanupHooks(): void {
  if (cleanupHooksRegistered) {
    return;
  }
  cleanupHooksRegistered = true;

  const closeClient = async () => {
    if (!authClient) {
      return;
    }
    const current = authClient;
    authClient = null;
    try {
      await current.close();
    } catch (error) {
      console.error("[auth] failed to close fn-token-auth client", error);
    }
  };

  process.once("SIGINT", () => {
    void closeClient();
  });
  process.once("SIGTERM", () => {
    void closeClient();
  });
}

function getAuthClient(): AuthClient {
  if (!authClient) {
    if (FN_AUTH_MODE === "sac") {
      authClient = createSacTokenAuth({
        sacEndpoint: FN_AUTH_SAC_ENDPOINT,
        timeoutMs: FN_AUTH_TIMEOUT_MS,
        enableCache: true,
        cacheTtlMs: FN_AUTH_CACHE_TTL_MS,
        machineId: FN_AUTH_MACHINE_ID,
        deviceIdPath: FN_AUTH_DEVICE_ID_PATH,
        entryEndpoint: FN_AUTH_ENTRY_ENDPOINT,
        entryTimeoutMs: FN_AUTH_ENTRY_TIMEOUT_MS,
        enableEntryCache: true,
        entryCacheTtlMs: FN_AUTH_ENTRY_CACHE_TTL_MS,
      });
    } else {
      authClient = createFnTokenAuth({
        timeoutMs: FN_AUTH_TIMEOUT_MS,
        enableCache: true,
        cacheTtlMs: FN_AUTH_CACHE_TTL_MS,
        machineId: FN_AUTH_MACHINE_ID,
        entryEndpoint: FN_AUTH_ENTRY_ENDPOINT,
        entryTimeoutMs: FN_AUTH_ENTRY_TIMEOUT_MS,
        enableEntryCache: true,
        entryCacheTtlMs: FN_AUTH_ENTRY_CACHE_TTL_MS,
      });
    }
    ensureCleanupHooks();
  }
  return authClient;
}

function isRetryable(error: unknown): boolean {
  if (!(error instanceof Error)) {
    return false;
  }
  return !NON_RETRYABLE_ERROR_NAMES.has(error.name);
}

function delay(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function withRetry<T>(operation: () => Promise<T>): Promise<T> {
  let lastError: unknown;

  for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
    try {
      return await operation();
    } catch (error) {
      lastError = error;
      if (attempt < MAX_RETRIES && isRetryable(error)) {
        await delay(RETRY_DELAY_MS * (attempt + 1));
        continue;
      }
      break;
    }
  }

  throw lastError;
}

export async function verifyFnOsToken(token: string): Promise<FnOsIdentity | boolean> {
  const client = getAuthClient();
  return withRetry(() => client.verifyFnOsToken(token) as Promise<FnOsIdentity | boolean>);
}

export async function verifyEntryToken(token: string): Promise<boolean> {
  return withRetry(() => getAuthClient().verifyEntryToken(token));
}
