function wantsJson(request: Request): boolean {
  const accept = request.headers.get("accept") || "";
  const upgrade = request.headers.get("upgrade")?.toLowerCase();
  const pathname = new URL(request.url).pathname;
  return upgrade === "websocket" || pathname.includes("/api/") || accept.includes("application/json");
}

function jsonResponse(status: number, payload: Record<string, unknown>): Response {
  return Response.json(payload, {
    status,
    headers: {
      "Cache-Control": "no-store",
    },
  });
}

function htmlResponse(status: number, title: string, message: string): Response {
  const body = `<!doctype html><html><head><meta charset="utf-8"><title>${title}</title></head><body><h1>${title}</h1><p>${message}</p></body></html>`;
  return new Response(body, {
    status,
    headers: {
      "Content-Type": "text/html; charset=utf-8",
      "Cache-Control": "no-store",
    },
  });
}

export function unauthorizedResponse(request: Request, reason: string): Response {
  if (wantsJson(request)) {
    return jsonResponse(401, { message: "Unauthorized", reason });
  }
  return htmlResponse(401, "Unauthorized", "请先登录飞牛 NAS OS 后再访问 OpenClaw monitor。");
}

export function forbiddenResponse(request: Request, reason: string): Response {
  if (wantsJson(request)) {
    return jsonResponse(403, { message: "Forbidden", reason });
  }
  return htmlResponse(403, "Forbidden", "当前请求来源无权访问 OpenClaw monitor。");
}

export function serviceUnavailableResponse(request: Request, reason: string): Response {
  if (wantsJson(request)) {
    return jsonResponse(503, { message: "Authentication service unavailable", reason });
  }
  return htmlResponse(503, "Authentication Unavailable", "fnOS 鉴权服务暂时不可用，请稍后重试。");
}
