import http from "node:http";
import { URL } from "node:url";

import { TransportConnectError, TransportTimeoutError } from "./errors.js";

/**
 * HTTP-over-unix-socket utility
 *
 * Supports both:
 * - Unix domain socket: endpoint = "/var/run/trim_sac.socket"
 * - TCP: endpoint = "tcp://127.0.0.1:38000"
 * - HTTP URL: endpoint = "http://192.168.9.222:5666"
 */

export async function httpRequest({
  endpoint,
  path,
  method = "GET",
  headers = {},
  body = null,
  timeoutMs = 5000
}) {
  const isUnixSocket = endpoint.startsWith("/");
  const isTcp = endpoint.startsWith("tcp://");

  const options = isUnixSocket
    ? buildUnixSocketOptions(endpoint, path, method, headers)
    : isTcp
    ? buildTcpOptions(endpoint, path, method, headers)
    : buildHttpOptions(endpoint, path, method, headers);

  return new Promise((resolve, reject) => {
    let timedOut = false;

    const request = http.request(options, (response) => {
      const chunks = [];

      response.on("data", (chunk) => {
        chunks.push(chunk);
      });

      response.on("end", () => {
        clearTimeout(timer);
        resolve({
          statusCode: response.statusCode ?? 0,
          bodyText: Buffer.concat(chunks).toString("utf8")
        });
      });

      response.on("error", (error) => {
        clearTimeout(timer);
        reject(
          new TransportConnectError("HTTP response read failed", {
            cause: error,
            details: { endpoint, path, method }
          })
        );
      });
    });

    const timer = setTimeout(() => {
      timedOut = true;
      request.destroy(new Error("timeout"));
    }, timeoutMs);

    request.on("error", (error) => {
      clearTimeout(timer);
      if (timedOut) {
        reject(
          new TransportTimeoutError(`HTTP request timed out after ${timeoutMs}ms`, {
            cause: error,
            details: { endpoint, path, method }
          })
        );
        return;
      }

      reject(
        new TransportConnectError("HTTP request failed", {
          cause: error,
          details: { endpoint, path, method }
        })
      );
    });

    if (body) {
      request.write(body);
    }
    request.end();
  });
}

function buildUnixSocketOptions(socketPath, path, method, headers) {
  return {
    socketPath,
    path,
    method,
    headers: {
      Host: "unix",
      ...headers
    }
  };
}

function buildTcpOptions(tcpUrl, path, method, headers) {
  const url = new URL(tcpUrl);
  return {
    hostname: url.hostname,
    port: Number(url.port),
    path,
    method,
    headers: {
      Host: `${url.hostname}:${url.port}`,
      ...headers
    }
  };
}

function buildHttpOptions(baseUrl, path, method, headers) {
  const url = new URL(path, baseUrl);
  return {
    hostname: url.hostname,
    port: url.port || (url.protocol === "https:" ? 443 : 80),
    path: url.pathname + url.search,
    method,
    headers: {
      Host: url.host,
      ...headers
    }
  };
}
