import { existsSync } from "fs";
import { rm } from "fs/promises";
import { parseJsonFromCommandOutput } from "./cli-json";
import { readLooseConfigFile } from "./config-file";
import type { InstanceRecord } from "./instances";
import { fileExists, readTextFileIfExists, writeTextFile } from "./node-fs";
import { runCommandText } from "./node-process";
import { activeConfigPath, openclawEnv, openclawSpawnCwd, requireOpenclawBinary, resolveOpenclawBinary as maybeResolveOpenclawBinary } from "./openclaw-instance";

type FeishuConnectionMode = "websocket" | "webhook";
type FeishuDmPolicy = "pairing" | "allowlist" | "open" | "disabled";
type FeishuGroupPolicy = "open" | "allowlist" | "disabled";
type WecomDmPolicy = "pairing" | "allowlist" | "open" | "disabled";
type ChannelKey = "feishu" | "wecom" | "dingtalk";

interface ConfigValidationResponse {
  valid: boolean;
  path: string;
  error?: string;
  errors?: string[];
}

interface FeishuAccountConfig {
  enabled?: boolean;
  appId?: string;
  appSecret?: string;
  [key: string]: unknown;
}

export interface FeishuConfigSnapshot {
  configured: boolean;
  appId: string;
  appSecretConfigured: boolean;
  enabled: boolean;
  connectionMode: FeishuConnectionMode;
  dmPolicy: FeishuDmPolicy;
  groupPolicy: FeishuGroupPolicy;
  requireMention: boolean;
}

export interface WecomConfigSnapshot {
  configured: boolean;
  botId: string;
  secretConfigured: boolean;
  enabled: boolean;
  websocketUrl: string;
  dmPolicy: WecomDmPolicy;
}

export interface DingtalkConfigSnapshot {
  configured: boolean;
  clientId: string;
  clientSecretConfigured: boolean;
  gatewayTokenConfigured: boolean;
  gatewayPasswordConfigured: boolean;
  gatewayAuthMode: string | null;
  gatewayAuthTokenConfigured: boolean;
  sessionTimeout: number;
  chatCompletionsEnabled: boolean;
}

export interface ChannelsConfigResponse {
  configPath: string;
  configExists: boolean;
  validation: {
    valid: boolean;
    message?: string;
  };
  configuredChannelIds: string[];
  feishu: FeishuConfigSnapshot;
  wecom: WecomConfigSnapshot;
  dingtalk: DingtalkConfigSnapshot;
}

export interface ChannelPluginStatus {
  channelKey: ChannelKey;
  pluginId: string;
  label: string;
  packageSpec: string;
  installed: boolean;
  source: "bundled" | "package" | "unknown";
  requiresRestart: boolean;
  docUrl: string;
  note?: string;
}

export interface ChannelPluginsResponse {
  plugins: ChannelPluginStatus[];
}

export interface FeishuConfigInput {
  appId: string;
  appSecret?: string | null;
}

export interface WecomConfigInput {
  botId: string;
  secret?: string | null;
}

export interface SaveChannelsConfigPayload {
  feishu?: FeishuConfigInput;
  wecom?: WecomConfigInput;
  dingtalk?: DingtalkConfigInput;
}

export interface DingtalkConfigInput {
  clientId: string;
  clientSecret?: string | null;
}

export interface InstallChannelPluginPayload {
  channelKey: ChannelKey;
}

export interface InstallChannelPluginResponse {
  channelKey: ChannelKey;
  pluginId: string;
  label: string;
  packageSpec: string;
  requiresRestart: boolean;
  stdout: string;
  stderr: string;
}

function asObject(value: unknown): Record<string, unknown> {
  return value && typeof value === "object" && !Array.isArray(value)
    ? (value as Record<string, unknown>)
    : {};
}

function asString(value: unknown): string | null {
  return typeof value === "string" && value.trim().length > 0 ? value.trim() : null;
}

function asBoolean(value: unknown, fallback: boolean): boolean {
  return typeof value === "boolean" ? value : fallback;
}

function asNumber(value: unknown, fallback: number): number {
  return typeof value === "number" && Number.isFinite(value) ? value : fallback;
}

function uniqueStrings(value: unknown): string[] {
  if (!Array.isArray(value)) {
    return [];
  }

  return Array.from(
    new Set(
      value
        .map((item) => (typeof item === "string" ? item.trim() : ""))
        .filter((item) => item.length > 0)
    )
  );
}

async function readConfigFile(path: string): Promise<Record<string, unknown>> {
  return readLooseConfigFile(path);
}

async function resolveOpenclawBinary(instance: InstanceRecord): Promise<string> {
  return requireOpenclawBinary(instance);
}

async function tryResolveOpenclawBinary(instance: InstanceRecord): Promise<string | null> {
  return maybeResolveOpenclawBinary(instance);
}

async function runOpenclawCommand(
  instance: InstanceRecord,
  args: string[]
): Promise<{ stdout: string; stderr: string; exitCode: number }> {
  const bin = await resolveOpenclawBinary(instance);
  return runCommandText([bin, ...args], {
    env: openclawEnv(instance),
    cwd: openclawSpawnCwd(instance),
  });
}

async function runOpenclawJsonCommand<T>(
  instance: InstanceRecord,
  args: string[]
): Promise<T> {
  const result = await runOpenclawCommand(instance, args);
  if (result.exitCode !== 0) {
    throw new Error(result.stderr || result.stdout || `openclaw ${args.join(" ")} failed`);
  }

  try {
    return parseJsonFromCommandOutput<T>(result.stdout);
  } catch {
    throw new Error(`Invalid JSON from openclaw ${args.join(" ")}`);
  }
}

async function getActiveConfigPath(instance: InstanceRecord): Promise<string> {
  return activeConfigPath(instance);
}

function makeJsonArg(value: unknown): string {
  return JSON.stringify(value);
}

async function setConfigValue(instance: InstanceRecord, path: string, value: unknown): Promise<void> {
  const result = await runOpenclawCommand(instance, ["config", "set", path, makeJsonArg(value), "--strict-json"]);
  if (result.exitCode !== 0) {
    throw new Error(result.stderr || result.stdout || `Failed to set ${path}`);
  }
}

function assignOrDelete(target: Record<string, unknown>, key: string, value: unknown): void {
  if (
    value === undefined
    || value === null
    || (typeof value === "string" && value.trim().length === 0)
    || (Array.isArray(value) && value.length === 0)
  ) {
    delete target[key];
    return;
  }

  target[key] = value;
}

function asArray(value: unknown): unknown[] {
  return Array.isArray(value) ? value : [];
}

function buildFeishuSnapshot(feishuConfigRaw: Record<string, unknown>): FeishuConfigSnapshot {
  const accountsRaw = asObject(feishuConfigRaw.accounts);
  const firstAccount = asObject(Object.values(accountsRaw)[0]) as FeishuAccountConfig;
  const appId = asString(feishuConfigRaw.appId) || asString(firstAccount.appId) || "";
  const appSecretConfigured = Boolean(asString(feishuConfigRaw.appSecret) || asString(firstAccount.appSecret));

  return {
    configured: Object.keys(feishuConfigRaw).length > 0,
    appId,
    appSecretConfigured,
    enabled: asBoolean(feishuConfigRaw.enabled, false),
    connectionMode:
      asString(feishuConfigRaw.connectionMode) === "webhook"
        ? "webhook"
        : "websocket",
    dmPolicy: (() => {
      const value = asString(feishuConfigRaw.dmPolicy);
      return value === "allowlist" || value === "open" || value === "disabled"
        ? value
        : "pairing";
    })(),
    groupPolicy: (() => {
      const value = asString(feishuConfigRaw.groupPolicy);
      return value === "open" || value === "disabled" ? value : "allowlist";
    })(),
    requireMention: asBoolean(feishuConfigRaw.requireMention, true),
  };
}

function buildDingtalkSnapshot(
  dingtalkConfigRaw: Record<string, unknown>,
  gatewayConfigRaw: Record<string, unknown>
): DingtalkConfigSnapshot {
  const gatewayAuth = asObject(gatewayConfigRaw.auth);
  const gatewayHttp = asObject(gatewayConfigRaw.http);
  const endpoints = asObject(gatewayHttp.endpoints);
  const chatCompletions = asObject(endpoints.chatCompletions);

  return {
    configured: Object.keys(dingtalkConfigRaw).length > 0,
    clientId: asString(dingtalkConfigRaw.clientId) || "",
    clientSecretConfigured: Boolean(asString(dingtalkConfigRaw.clientSecret)),
    gatewayTokenConfigured: Boolean(asString(dingtalkConfigRaw.gatewayToken)),
    gatewayPasswordConfigured: Boolean(asString(dingtalkConfigRaw.gatewayPassword)),
    gatewayAuthMode: asString(gatewayAuth.mode),
    gatewayAuthTokenConfigured: Boolean(asString(gatewayAuth.token)),
    sessionTimeout: asNumber(dingtalkConfigRaw.sessionTimeout, 1_800_000),
    chatCompletionsEnabled: asBoolean(chatCompletions.enabled, false),
  };
}

function buildWecomSnapshot(wecomConfigRaw: Record<string, unknown>): WecomConfigSnapshot {
  return {
    configured: Object.keys(wecomConfigRaw).length > 0,
    botId: asString(wecomConfigRaw.botId) || "",
    secretConfigured: Boolean(asString(wecomConfigRaw.secret)),
    enabled: asBoolean(wecomConfigRaw.enabled, false),
    websocketUrl: asString(wecomConfigRaw.websocketUrl) || "wss://openws.work.weixin.qq.com",
    dmPolicy: (() => {
      const value = asString(wecomConfigRaw.dmPolicy);
      return value === "allowlist" || value === "open" || value === "disabled"
        ? value
        : "pairing";
    })(),
  };
}

function normalizeFeishuInput(input: FeishuConfigInput): { appId: string; appSecret: string | null } {
  const appId = input.appId.trim();
  if (!appId) {
    throw new Error("飞书 App ID 不能为空");
  }

  return {
    appId,
    appSecret: typeof input.appSecret === "string" ? input.appSecret.trim() : null,
  };
}

function normalizeWecomInput(input: WecomConfigInput): { botId: string; secret: string | null } {
  const botId = input.botId.trim();
  if (!botId) {
    throw new Error("企业微信 Bot ID 不能为空");
  }

  return {
    botId,
    secret: typeof input.secret === "string" ? input.secret.trim() : null,
  };
}

export async function getChannelsConfig(instance: InstanceRecord): Promise<ChannelsConfigResponse> {
  const binaryPath = await tryResolveOpenclawBinary(instance);
  const activeConfigPath = await getActiveConfigPath(instance);
  const configExists = existsSync(activeConfigPath);
  const config = await readConfigFile(activeConfigPath);
  const channelsConfig = asObject(config.channels);
  const feishuConfig = asObject(channelsConfig.feishu);
  const wecomConfig = asObject(channelsConfig.wecom);
  const dingtalkConfig = asObject(channelsConfig["dingtalk-connector"]);
  const gatewayConfig = asObject(config.gateway);

  let validation: ConfigValidationResponse = {
    valid: true,
    path: activeConfigPath,
  };

  if (binaryPath && configExists) {
    try {
      validation = await runOpenclawJsonCommand<ConfigValidationResponse>(
        instance,
        ["config", "validate", "--json"]
      );
    } catch (error) {
      validation = {
        valid: false,
        path: activeConfigPath,
        errors: [error instanceof Error ? error.message : String(error)],
      };
    }
  }

  return {
    configPath: validation.path || activeConfigPath,
    configExists,
    validation: {
      valid: Boolean(validation.valid),
      message: Array.isArray(validation.errors) && validation.errors.length > 0
        ? validation.errors.join("; ")
        : typeof validation.error === "string" && validation.error.length > 0
          ? validation.error
          : undefined,
    },
    configuredChannelIds: Object.keys(channelsConfig).sort(),
    feishu: buildFeishuSnapshot(feishuConfig),
    wecom: buildWecomSnapshot(wecomConfig),
    dingtalk: buildDingtalkSnapshot(dingtalkConfig, gatewayConfig),
  };
}

function normalizeDingtalkInput(input: DingtalkConfigInput): {
  clientId: string;
  clientSecret: string | null;
} {
  const clientId = input.clientId.trim();
  if (!clientId) {
    throw new Error("钉钉 Client ID 不能为空");
  }

  return {
    clientId,
    clientSecret: typeof input.clientSecret === "string" ? input.clientSecret.trim() : null,
  };
}

function pluginDescriptor(channelKey: ChannelKey): Omit<ChannelPluginStatus, "installed" | "source"> {
  if (channelKey === "feishu") {
    return {
      channelKey,
      pluginId: "feishu",
      label: "飞书",
      packageSpec: "@openclaw/feishu",
      requiresRestart: true,
      docUrl: "https://docs.openclaw.ai/channels/feishu",
      note: "OpenClaw 官方文档说明当前版本通常已内置 Feishu；旧版本或自定义安装可手动安装。",
    };
  }

  if (channelKey === "wecom") {
    return {
      channelKey,
      pluginId: "wecom-openclaw-plugin",
      label: "企业微信",
      packageSpec: "@wecom/wecom-openclaw-plugin",
      requiresRestart: true,
      docUrl: "https://open.work.weixin.qq.com/help?doc_id=21657",
      note: "插件 ID 是 wecom-openclaw-plugin，配置里的 channel key 是 wecom；两者不是同一个字段。",
    };
  }

  if (channelKey === "dingtalk") {
    return {
      channelKey,
      pluginId: "dingtalk-connector",
      label: "钉钉",
      packageSpec: "@dingtalk-real-ai/dingtalk-connector",
      requiresRestart: true,
      docUrl: "https://open.dingtalk.com/document/dingstart/build-dingtalk-ai-employees",
      note: "这里按你提供的插件包名执行安装；字段设计应以钉钉开放平台文档和插件自身 schema 为准。",
    };
  }

  return {
    channelKey,
    pluginId: "dingtalk-connector",
    label: "钉钉",
    packageSpec: "@dingtalk-real-ai/dingtalk-connector",
    requiresRestart: true,
    docUrl: "https://open.dingtalk.com/document/dingstart/build-dingtalk-ai-employees",
    note: "这里按你提供的插件包名执行安装；字段设计应以钉钉开放平台文档和插件自身 schema 为准。",
  };
}

export async function getChannelPlugins(instance: InstanceRecord): Promise<ChannelPluginsResponse> {
  let pluginListStdout = "";
  const binaryPath = await tryResolveOpenclawBinary(instance);
  if (binaryPath) {
    const result = await runOpenclawCommand(instance, ["plugins", "list"]);
    if (result.exitCode === 0) {
      pluginListStdout = result.stdout.toLowerCase();
    }
  }

  function listed(descriptor: Omit<ChannelPluginStatus, "installed" | "source">, aliases: string[]): boolean {
    const patterns = [
      descriptor.packageSpec.toLowerCase(),
      descriptor.pluginId.toLowerCase(),
      descriptor.channelKey.toLowerCase(),
      ...aliases.map((alias) => alias.toLowerCase()),
    ];

    return patterns.some((pattern) => pattern.length > 0 && pluginListStdout.includes(pattern));
  }

  const plugins: ChannelPluginStatus[] = [
    (() => {
      const descriptor = pluginDescriptor("feishu");
      const installed = listed(descriptor, ["lark"]);
      return {
        ...descriptor,
        installed,
        source: installed ? "package" : "unknown",
      } satisfies ChannelPluginStatus;
    })(),
    (() => {
      const descriptor = pluginDescriptor("wecom");
      const installed = listed(descriptor, ["wecom-openclaw-plugin", "wechat-work", "work-wechat"]);
      return {
        ...descriptor,
        installed,
        source: installed ? "package" : "unknown",
      } satisfies ChannelPluginStatus;
    })(),
    (() => {
      const descriptor = pluginDescriptor("dingtalk");
      const installed = listed(descriptor, ["dingtalk-connector", "dingding"]);
      return {
        ...descriptor,
        installed,
        source: installed ? "package" : "unknown",
      } satisfies ChannelPluginStatus;
    })(),
  ];

  return { plugins };
}

export async function installChannelPlugin(
  instance: InstanceRecord,
  payload: InstallChannelPluginPayload
): Promise<InstallChannelPluginResponse> {
  if (!(await tryResolveOpenclawBinary(instance))) {
    throw new Error("OpenClaw 尚未安装，无法安装渠道插件。");
  }

  if (payload.channelKey !== "feishu" && payload.channelKey !== "wecom" && payload.channelKey !== "dingtalk") {
    throw new Error("Unsupported channel plugin");
  }

  const descriptor = pluginDescriptor(payload.channelKey);
  const result = await runOpenclawCommand(instance, ["plugins", "install", descriptor.packageSpec]);
  if (result.exitCode !== 0) {
    throw new Error(result.stderr || result.stdout || `安装 ${descriptor.packageSpec} 失败`);
  }

  return {
    channelKey: descriptor.channelKey,
    pluginId: descriptor.pluginId,
    label: descriptor.label,
    packageSpec: descriptor.packageSpec,
    requiresRestart: descriptor.requiresRestart,
    stdout: result.stdout,
    stderr: result.stderr,
  };
}

export async function saveChannelsConfig(
  instance: InstanceRecord,
  payload: SaveChannelsConfigPayload
): Promise<ChannelsConfigResponse> {
  if (!(await tryResolveOpenclawBinary(instance))) {
    throw new Error("OpenClaw 尚未安装，无法保存消息渠道配置。");
  }

  if (payload.wecom && typeof payload.wecom === "object") {
    const normalized = normalizeWecomInput(payload.wecom);
    const configPath = await getActiveConfigPath(instance);
    const currentConfig = await readConfigFile(configPath);
    const channelsRaw = asObject(currentConfig.channels);
    const currentWecom = asObject(channelsRaw.wecom);
    const currentSecret = asString(currentWecom.secret);
    const nextSecret = normalized.secret || currentSecret;

    if (!nextSecret) {
      throw new Error("企业微信 Secret 不能为空");
    }

    const nextWecom: Record<string, unknown> = { ...currentWecom };
    nextWecom.botId = normalized.botId;
    nextWecom.secret = nextSecret;
    nextWecom.enabled = true;
    nextWecom.websocketUrl = asString(currentWecom.websocketUrl) || "wss://openws.work.weixin.qq.com";
    nextWecom.dmPolicy = "pairing";

    const originalSnapshot = {
      exists: await fileExists(configPath),
      text: (await readTextFileIfExists(configPath)) || "",
    };

    try {
      await setConfigValue(instance, "channels.wecom", nextWecom);

      const validation = await runOpenclawJsonCommand<ConfigValidationResponse>(
        instance,
        ["config", "validate", "--json"]
      );

      if (!validation.valid) {
        throw new Error(
          Array.isArray(validation.errors) && validation.errors.length > 0
            ? validation.errors.join("; ")
            : validation.error || "Config validation failed"
        );
      }
    } catch (error) {
      if (originalSnapshot.exists) {
        await writeTextFile(configPath, originalSnapshot.text);
      } else if (await fileExists(configPath)) {
        await rm(configPath, { force: true });
      }
      throw error;
    }

    return getChannelsConfig(instance);
  }

  if (payload.dingtalk && typeof payload.dingtalk === "object") {
    const normalized = normalizeDingtalkInput(payload.dingtalk);
    const configPath = await getActiveConfigPath(instance);
    const currentConfig = await readConfigFile(configPath);
    const channelsRaw = asObject(currentConfig.channels);
    const currentDingtalk = asObject(channelsRaw["dingtalk-connector"]);
    const gatewayRaw = asObject(currentConfig.gateway);
    const currentAuth = asObject(gatewayRaw.auth);
    const currentHttp = asObject(gatewayRaw.http);
    const currentEndpoints = asObject(currentHttp.endpoints);
    const currentChatCompletions = asObject(currentEndpoints.chatCompletions);

    const currentClientSecret = asString(currentDingtalk.clientSecret);
    const currentGatewayToken = asString(currentAuth.token) || asString(currentDingtalk.gatewayToken);
    const currentGatewayPassword = asString(currentDingtalk.gatewayPassword);
    const currentSessionTimeout = asNumber(currentDingtalk.sessionTimeout, 1_800_000);

    const nextClientSecret = normalized.clientSecret || currentClientSecret;
    if (!nextClientSecret) {
      throw new Error("钉钉 Client Secret 不能为空");
    }

    const nextGatewayToken = currentGatewayToken || crypto.randomUUID().replace(/-/g, "");
    const nextGatewayPassword = currentGatewayPassword;

    const nextDingtalk: Record<string, unknown> = { ...currentDingtalk };
    nextDingtalk.clientId = normalized.clientId;
    nextDingtalk.clientSecret = nextClientSecret;
    nextDingtalk.gatewayToken = nextGatewayToken;
    nextDingtalk.sessionTimeout = currentSessionTimeout;
    assignOrDelete(nextDingtalk, "gatewayPassword", nextGatewayPassword);

    const nextGatewayAuth: Record<string, unknown> = {
      ...currentAuth,
      mode: "token",
      token: nextGatewayToken,
    };

    const nextGatewayHttp: Record<string, unknown> = {
      ...currentHttp,
      endpoints: {
        ...currentEndpoints,
        chatCompletions: {
          ...currentChatCompletions,
          enabled: true,
        },
      },
    };

    const originalSnapshot = {
      exists: await fileExists(configPath),
      text: (await readTextFileIfExists(configPath)) || "",
    };

    try {
      await setConfigValue(instance, "channels.dingtalk-connector", nextDingtalk);
      await setConfigValue(instance, "gateway.auth", nextGatewayAuth);
      await setConfigValue(instance, "gateway.http", nextGatewayHttp);

      const validation = await runOpenclawJsonCommand<ConfigValidationResponse>(
        instance,
        ["config", "validate", "--json"]
      );

      if (!validation.valid) {
        throw new Error(
          Array.isArray(validation.errors) && validation.errors.length > 0
            ? validation.errors.join("; ")
            : validation.error || "Config validation failed"
        );
      }
    } catch (error) {
      if (originalSnapshot.exists) {
        await writeTextFile(configPath, originalSnapshot.text);
      } else if (await fileExists(configPath)) {
        await rm(configPath, { force: true });
      }
      throw error;
    }

    return getChannelsConfig(instance);
  }

  if (!payload.feishu || typeof payload.feishu !== "object") {
    throw new Error("缺少可保存的渠道配置");
  }

  const normalized = normalizeFeishuInput(payload.feishu);
  const configPath = await getActiveConfigPath(instance);
  const currentConfig = await readConfigFile(configPath);
  const channelsRaw = asObject(currentConfig.channels);
  const currentFeishu = asObject(channelsRaw.feishu);
  const currentAccounts = asObject(currentFeishu.accounts);
  const firstAccount = asObject(Object.values(currentAccounts)[0]);
  const nextFeishu: Record<string, unknown> = { ...currentFeishu };
  const currentAppSecret = asString(currentFeishu.appSecret) || asString(firstAccount.appSecret);
  const nextAppSecret = normalized.appSecret || currentAppSecret;
  if (!nextAppSecret) {
    throw new Error("飞书 App Secret 不能为空");
  }

  nextFeishu.appId = normalized.appId;
  nextFeishu.appSecret = nextAppSecret;
  nextFeishu.enabled = true;
  nextFeishu.connectionMode = "websocket";
  nextFeishu.dmPolicy = "pairing";
  nextFeishu.groupPolicy = "allowlist";
  nextFeishu.requireMention = true;

  const originalSnapshot = {
    exists: await fileExists(configPath),
    text: (await readTextFileIfExists(configPath)) || "",
  };

  try {
    await setConfigValue(instance, "channels.feishu", nextFeishu);

    const validation = await runOpenclawJsonCommand<ConfigValidationResponse>(
      instance,
      ["config", "validate", "--json"]
    );

    if (!validation.valid) {
      throw new Error(
        Array.isArray(validation.errors) && validation.errors.length > 0
          ? validation.errors.join("; ")
          : validation.error || "Config validation failed"
      );
    }
  } catch (error) {
    if (originalSnapshot.exists) {
      await writeTextFile(configPath, originalSnapshot.text);
    } else if (await fileExists(configPath)) {
      await rm(configPath, { force: true });
    }
    throw error;
  }

  return getChannelsConfig(instance);
}
