import { Hono } from "hono";
import { createInstance, getInstance, listInstances } from "../lib/instances";
import { getInstanceStatus } from "../lib/status";

const app = new Hono();

app.get("/", async (c) => {
  const instances = await Promise.all(
    listInstances().map(async (instance) => getInstanceStatus(instance, c))
  );
  return c.json({ instances });
});

app.get("/:instanceId", async (c) => {
  const instance = getInstance(c.req.param("instanceId"));
  if (!instance) {
    return c.json({ message: "Instance not found" }, 404);
  }

  return c.json(await getInstanceStatus(instance, c));
});

app.post("/", async (c) => {
  const body: { ownerId?: string; displayName?: string } = await c.req
    .json<{ ownerId?: string; displayName?: string }>()
    .catch(() => ({} as { ownerId?: string; displayName?: string }));
  const ownerId = body.ownerId?.trim();
  if (!ownerId) {
    return c.json({ message: "ownerId is required" }, 400);
  }

  const instance = createInstance({
    ownerId,
    displayName: body.displayName,
  });

  return c.json(instance, 201);
});

export default app;
