import { createAdaptorServer } from "@hono/node-server";
import type { IncomingMessage } from "node:http";
import type { Duplex } from "node:stream";
import { Hono } from "hono";
import type { Context } from "hono";
import { cors } from "hono/cors";
import { join, resolve } from "path";
import { MONITOR_BASE_PATH, isLikelyDevEnvironment } from "./lib/config";
import { accessDeniedResponse, shouldAllowClientIp } from "./lib/access-control";
import {
  FN_AUTH_COOKIE_NAME,
  FN_AUTH_ENABLED,
  FN_AUTH_ENTRY_COOKIE_NAME,
  FN_AUTH_REQUIRE_SAME_ORIGIN,
} from "./lib/auth/config";
import { authenticateRequest } from "./lib/auth/request-auth";
import { startRuntimeReconciler } from "./lib/runtime-state";
import { shouldUseSystemOpenclaw } from "./lib/openclaw-platform";
import { DEFAULT_INSTANCE_ID } from "./lib/config";
import { ensureDevModeConfig } from "./lib/dev-config";
import {
  maybeHandleProxyWebSocketUpgrade,
  maybeProxyHttpRequest,
} from "./lib/proxy-gateway";
import { fileExists, readStaticFile } from "./lib/node-fs";
import gatewayRoute from "./routes/gateway";
import installRoute from "./routes/install";
import instancesRoute from "./routes/instances";
import channelsRoute from "./routes/channels";
import modelsRoute from "./routes/models";
import statusRoute from "./routes/status";

const basePath = MONITOR_BASE_PATH;
const apiBase = `${basePath}/api`;
const assetsBase = `${basePath}/assets`;
const moduleDir = __dirname;
const staticDir =
  process.env.STATIC_DIR || resolve(moduleDir, "../../web/dist");
const port = parseInt(process.env.PORT || "3000", 10);

function requestUrlFromIncoming(incoming: IncomingMessage): string {
  const host = incoming.headers.host || `127.0.0.1:${port}`;
  const protocol = "https" in incoming.socket && (incoming.socket as { encrypted?: boolean }).encrypted ? "https" : "http";
  return `${protocol}://${host}${incoming.url || "/"}`;
}

function buildRequestFromIncoming(incoming: IncomingMessage): Request {
  const headers = new Headers();
  for (const [key, value] of Object.entries(incoming.headers)) {
    if (Array.isArray(value)) {
      for (const entry of value) {
        headers.append(key, entry);
      }
      continue;
    }
    if (typeof value === "string") {
      headers.set(key, value);
    }
  }

  return new Request(requestUrlFromIncoming(incoming), {
    method: incoming.method || "GET",
    headers,
  });
}

async function writeResponseToSocket(socket: Duplex, response: Response): Promise<void> {
  const body = response.body ? Buffer.from(await response.arrayBuffer()) : Buffer.alloc(0);
  const headers = new Headers(response.headers);
  headers.set("Connection", "close");
  headers.set("Content-Length", String(body.length));

  const statusLine = `HTTP/1.1 ${response.status} ${response.statusText || "Error"}`;
  const headerLines = Array.from(headers.entries()).map(([key, value]) => `${key}: ${value}`);
  socket.write(`${statusLine}\r\n${headerLines.join("\r\n")}\r\n\r\n`);
  socket.end(body);
}

async function bootstrap(): Promise<void> {
  const app = new Hono();
  const isDev = isLikelyDevEnvironment();
  const useSystemOpenclaw = shouldUseSystemOpenclaw(DEFAULT_INSTANCE_ID);

  console.log(`[monitor] Environment: ${isDev ? "development" : "production"}`);
  console.log(`[monitor] OpenClaw mode: ${useSystemOpenclaw ? "system (global)" : "managed (isolated)"}`);
  if (useSystemOpenclaw) {
    console.log(`[monitor] System OpenClaw config: ~/.openclaw/openclaw.json`);
    console.log(`[monitor] Note: Monitor will use your global OpenClaw installation`);
  } else {
    console.log(`[monitor] Managed OpenClaw config: DATA_ROOT/home/.openclaw/openclaw.json`);
  }

  if (isDev && useSystemOpenclaw) {
    await ensureDevModeConfig();
  }

  startRuntimeReconciler();

  app.use(`${apiBase}/*`, cors());
  app.use(`${apiBase}/*`, async (c, next) => {
    const startedAt = Date.now();
    console.log(`[api] -> ${c.req.method} ${c.req.path}`);
    await next();
    console.log(`[api] <- ${c.req.method} ${c.req.path} ${c.res.status} ${Date.now() - startedAt}ms`);
  });

  app.onError((error, c) => {
    console.error(`[api:error] ${c.req.method} ${c.req.path}`);
    console.error(error instanceof Error ? error.stack || error.message : String(error));
    return c.json(
      { message: error instanceof Error ? error.message : String(error) },
      500
    );
  });

  app.route(`${apiBase}/status`, statusRoute);
  app.route(`${apiBase}/install`, installRoute);
  app.route(`${apiBase}/gateway`, gatewayRoute);
  app.route(`${apiBase}/instances`, instancesRoute);
  app.route(`${apiBase}/models`, modelsRoute);
  app.route(`${apiBase}/channels`, channelsRoute);

  app.get(`${apiBase}/health`, (c) => {
    return c.json({ status: "ok", port: process.env.PORT || 3000 });
  });

  app.get(`${assetsBase}/*`, async (c) => {
    const requestPath =
      basePath !== "" && c.req.path.startsWith(basePath)
        ? c.req.path.slice(basePath.length)
        : c.req.path;
    const filePath = join(staticDir, requestPath);
    if (!(await fileExists(filePath))) {
      return c.notFound();
    }

    const file = await readStaticFile(filePath);
    return new Response(file.body, {
      headers: {
        "Content-Length": String(file.size),
        "Content-Type": file.contentType,
      },
    });
  });

  const indexHandler = async (c: Context) => {
    const indexPath = join(staticDir, "index.html");
    if (!(await fileExists(indexPath))) {
      return c.text("index.html not found. Run 'pnpm build:web' first.", 404);
    }

    const file = await readStaticFile(indexPath);
    return new Response(file.body, {
      headers: {
        "Content-Length": String(file.size),
        "Content-Type": "text/html; charset=utf-8",
      },
    });
  };

  if (basePath === "") {
    app.get("*", indexHandler);
  } else {
    app.get(basePath, indexHandler);
    app.get(`${basePath}/`, indexHandler);
    app.get(`${basePath}/*`, indexHandler);
  }

  const server = createAdaptorServer({
    fetch: async (request, env) => {
      const clientIp = env.incoming.socket.remoteAddress;

      if (!shouldAllowClientIp(clientIp)) {
        return accessDeniedResponse(clientIp);
      }

      const authResult = await authenticateRequest(request);
      if (!authResult.ok) {
        return authResult.response;
      }

      const proxiedHttp = await maybeProxyHttpRequest(request, clientIp);
      if (proxiedHttp !== null) {
        return proxiedHttp;
      }

      return app.fetch(request);
    },
  });

  server.on("upgrade", async (incoming, socket, head) => {
    try {
      const request = buildRequestFromIncoming(incoming);
      const clientIp = incoming.socket.remoteAddress;

      if (!shouldAllowClientIp(clientIp)) {
        await writeResponseToSocket(socket, accessDeniedResponse(clientIp));
        return;
      }

      const authResult = await authenticateRequest(request);
      if (!authResult.ok) {
        await writeResponseToSocket(socket, authResult.response);
        return;
      }

      const handled = await maybeHandleProxyWebSocketUpgrade(
        request,
        incoming,
        socket,
        head,
        clientIp
      );

      if (!handled) {
        socket.destroy();
      }
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      await writeResponseToSocket(socket, new Response(message, { status: 500 }));
    }
  });

  server.on("error", (error) => {
    console.error("[monitor] server listen failed");
    console.error(error instanceof Error ? error.stack || error.message : String(error));
    process.exit(1);
  });

  server.listen(port, () => {
    console.log(`Server is running on http://localhost:${port}`);
    console.log(`Serving static files from: ${staticDir}`);
    console.log(`Base path: ${basePath || "/"}`);
    console.log(`fnOS auth enabled: ${FN_AUTH_ENABLED ? "yes" : "no"}`);
    console.log(`auth cookies: ${FN_AUTH_COOKIE_NAME}, ${FN_AUTH_ENTRY_COOKIE_NAME}`);
    console.log(`fnOS same-origin guard: ${FN_AUTH_REQUIRE_SAME_ORIGIN ? "yes" : "no"}`);
  });
}

void bootstrap().catch((error) => {
  console.error("[monitor] bootstrap failed");
  console.error(error instanceof Error ? error.stack || error.message : String(error));
  process.exit(1);
});
