import { homedir, tmpdir } from "os";

const configuredBasePath = process.env.BASE_PATH || "/opc-monitor";
const fnnasDataRoot = process.env.TRIM_PKGHOME
  ? `${process.env.TRIM_PKGHOME}/data`
  : null;

export const DATA_ROOT = process.env.OPENCLAW_DATA_DIR || fnnasDataRoot || "/tmp/openclaw-data";
export const DEFAULT_INSTANCE_ID = process.env.OPENCLAW_DEFAULT_INSTANCE_ID || "default";
export const MONITOR_BASE_PATH =
  configuredBasePath === "/"
    ? ""
    : `/${configuredBasePath}`.replace(/\/+/g, "/").replace(/\/$/, "");
export const MONITOR_DB_DIR = `${DATA_ROOT}/monitor`;
export const MONITOR_DB_PATH = `${MONITOR_DB_DIR}/monitor.sqlite`;
export const SYSTEM_OPENCLAW_CONFIG_PATH = `${homedir()}/.openclaw/openclaw.json`;
export const SYSTEM_OPENCLAW_LOG_PATH = `${homedir()}/.openclaw/logs/gateway.log`;
export const SYSTEM_OPENCLAW_RUNTIME_LOG_DIR = `${tmpdir()}/openclaw`;
export const MONITOR_ACCESS_MODE = process.env.MONITOR_ACCESS_MODE === "public" ? "public" : "lan";
export const OPENCLAW_NPM_REGISTRY = process.env.OPENCLAW_NPM_REGISTRY || "https://registry.npmmirror.com/";
export const SOUL_MD_SRC = process.env.SOUL_MD_SRC || null;

export function normalizePublicBasePath(value: string): string {
  if (!value || value === "/") {
    return "/";
  }

  const normalized = value.startsWith("/") ? value : `/${value}`;
  return normalized.endsWith("/") ? normalized : `${normalized}/`;
}

export function buildInstanceProxyBasePath(instanceId: string): string {
  const suffix = `/${instanceId}`;
  return MONITOR_BASE_PATH === "" ? suffix : `${MONITOR_BASE_PATH}${suffix}`;
}

export function isLikelyDevEnvironment(): boolean {
  if (process.env.OPENCLAW_DEV_MODE === "1") {
    return true;
  }
  if (process.env.OPENCLAW_DEV_MODE === "0") {
    return false;
  }
  if (process.env.OPENCLAW_USE_SYSTEM_CONFIG === "1") {
    return true;
  }
  if (process.env.OPENCLAW_USE_SYSTEM_CONFIG === "0") {
    return false;
  }
  if (process.env.NODE_ENV === "production") {
    return false;
  }
  if (process.env.BUN_WATCH === "1") {
    return true;
  }

  const normalizedArgs = process.argv.map((arg) => arg.replace(/\\/g, "/"));

  return normalizedArgs.some((arg) =>
    arg === "--watch" ||
    arg === "-w" ||
    arg === "src/index.ts" ||
    arg.endsWith("/src/index.ts")
  );
}
