import { MONITOR_ACCESS_MODE } from "./config";

function normalizeIp(value: string | null | undefined): string | null {
  if (!value) {
    return null;
  }

  const trimmed = value.trim();
  if (!trimmed) {
    return null;
  }

  if (trimmed.startsWith("::ffff:")) {
    return trimmed.slice(7);
  }

  return trimmed;
}

function isLoopback(ip: string): boolean {
  return ip === "127.0.0.1" || ip === "::1";
}

function isPrivateIpv4(ip: string): boolean {
  const parts = ip.split(".").map((part) => Number(part));
  if (parts.length !== 4 || parts.some((part) => !Number.isInteger(part) || part < 0 || part > 255)) {
    return false;
  }

  const [first, second] = parts;
  if (first === 10) {
    return true;
  }
  if (first === 172 && second >= 16 && second <= 31) {
    return true;
  }
  if (first === 192 && second === 168) {
    return true;
  }
  if (first === 169 && second === 254) {
    return true;
  }
  return false;
}

function isPrivateIpv6(ip: string): boolean {
  const lower = ip.toLowerCase();
  return lower.startsWith("fc") || lower.startsWith("fd") || lower.startsWith("fe8") || lower.startsWith("fe9") || lower.startsWith("fea") || lower.startsWith("feb");
}

export function isLanClientIp(ip: string | null | undefined): boolean {
  const normalized = normalizeIp(ip);
  if (!normalized) {
    return false;
  }

  if (isLoopback(normalized)) {
    return true;
  }

  if (normalized.includes(".")) {
    return isPrivateIpv4(normalized);
  }

  if (normalized.includes(":")) {
    return isPrivateIpv6(normalized);
  }

  return false;
}

export function shouldAllowClientIp(ip: string | null | undefined): boolean {
  if (MONITOR_ACCESS_MODE === "public") {
    return true;
  }

  return isLanClientIp(ip);
}

export function accessDeniedResponse(ip: string | null | undefined): Response {
  const message = {
    message: "Access denied: monitor is restricted to LAN and localhost clients.",
    clientIp: normalizeIp(ip),
    accessMode: MONITOR_ACCESS_MODE,
  };

  return Response.json(message, { status: 403 });
}
