import { rmSync } from "fs";
import type { InstanceRecord } from "./instances";
import { listInstances, updateInstance } from "./instances";
import { fileExists, readTextFile } from "./node-fs";
import { readInstancePort, resolveOpenclawBinary } from "./openclaw-instance";
import { findListeningPids, getProcessStartTime, isPidAlive } from "./process-control";

export interface InstanceRuntimeState {
  installed: boolean;
  binaryPath: string | null;
  port: number | null;
  running: boolean;
  pid: string | null;
  pidAlive: boolean;
  startedAt: number | null;
}

async function resolveBinaryPath(instance: InstanceRecord): Promise<string | null> {
  return resolveOpenclawBinary(instance);
}

export async function isPortListening(port: number): Promise<boolean> {
  try {
    const res = await fetch(`http://127.0.0.1:${port}`, {
      method: "HEAD",
      signal: AbortSignal.timeout(2000),
    });
    await res.body?.cancel();
    return true;
  } catch {
    return false;
  }
}

async function readPidFile(instance: InstanceRecord): Promise<string | null> {
  try {
    if (!(await fileExists(instance.pidPath))) {
      return null;
    }
    const value = (await readTextFile(instance.pidPath)).trim();
    return value || null;
  } catch {
    return null;
  }
}

function desiredStatus(installed: boolean, running: boolean): string {
  if (!installed) {
    return "not_installed";
  }
  return running ? "running" : "stopped";
}

export async function probeInstanceRuntime(instance: InstanceRecord): Promise<InstanceRuntimeState> {
  const binaryPath = await resolveBinaryPath(instance);
  const installed = Boolean(binaryPath);
  const port = installed ? (await readInstancePort(instance)) ?? instance.gatewayPort : null;
  const running = port ? await isPortListening(port) : false;
  let pid = await readPidFile(instance);
  let pidAlive = isPidAlive(pid);

  if (running && !pidAlive && port) {
    const portPid = (await findListeningPids(port))[0] || null;
    if (portPid && isPidAlive(portPid)) {
      pid = portPid;
      pidAlive = true;
    }
  }

  const startedAt = running && pidAlive ? await getProcessStartTime(pid) : null;

  return {
    installed,
    binaryPath,
    port,
    running,
    pid,
    pidAlive,
    startedAt,
  };
}

export async function reconcileInstanceRuntime(
  instance: InstanceRecord,
  existingRuntime?: InstanceRuntimeState
): Promise<void> {
  const runtime = existingRuntime ?? await probeInstanceRuntime(instance);
  const nextStatus = desiredStatus(runtime.installed, runtime.running);
  const nextPort = runtime.port;

  if (!runtime.running && !runtime.pidAlive) {
    try {
      rmSync(instance.pidPath, { force: true });
    } catch {
      // ignore stale pid cleanup failures
    }
  }

  if (instance.status !== nextStatus || instance.gatewayPort !== nextPort) {
    updateInstance(instance.id, {
      status: nextStatus,
      gatewayPort: nextPort,
    });
  }
}

let reconcileTimer: ReturnType<typeof setInterval> | null = null;
let reconcileInFlight = false;

export async function reconcileAllInstances(): Promise<void> {
  if (reconcileInFlight) {
    return;
  }

  reconcileInFlight = true;
  try {
    const instances = listInstances();
    await Promise.all(instances.map((instance) => reconcileInstanceRuntime(instance)));
  } finally {
    reconcileInFlight = false;
  }
}

export function startRuntimeReconciler(): void {
  if (reconcileTimer) {
    return;
  }

  void reconcileAllInstances().catch((error) => {
    console.error("[monitor] initial runtime reconciliation failed", error);
  });

  const intervalMs = Number(process.env.MONITOR_RECONCILE_INTERVAL_MS || 30000);
  reconcileTimer = setInterval(() => {
    void reconcileAllInstances().catch((error) => {
      console.error("[monitor] runtime reconciliation failed", error);
    });
  }, Number.isFinite(intervalMs) && intervalMs > 0 ? intervalMs : 30000);
}
