import { httpRequest } from "../core/http-transport.js";
import { FnOsAuthBackendError, TokenFormatError } from "../core/errors.js";

const DEFAULT_SAC_ENDPOINT = "/var/run/trim_sac.socket";
const FNOS_VERIFY_PATH = "/sac/rpcproxy/v1/new-user-guide/status";
const DEFAULT_TIMEOUT_MS = 2000;

export class SacFnosClient {
  #endpoint;
  #timeoutMs;

  constructor({ endpoint = DEFAULT_SAC_ENDPOINT, timeoutMs = DEFAULT_TIMEOUT_MS } = {}) {
    this.#endpoint = endpoint;
    this.#timeoutMs = timeoutMs;
  }

  async verify(token, { timeoutMs = this.#timeoutMs } = {}) {
    const normalizedToken = requireNonEmptyString(token, "fnos token is required");

    const { statusCode, bodyText } = await httpRequest({
      endpoint: this.#endpoint,
      path: FNOS_VERIFY_PATH,
      method: "GET",
      headers: {
        Authorization: `trim ${normalizedToken}`
      },
      timeoutMs
    });

    // HTTP 200 = valid admin token
    // HTTP 401 = invalid/missing token
    // Other codes = unexpected
    if (statusCode === 200) {
      return true;
    }

    if (statusCode === 401) {
      return false;
    }

    throw new FnOsAuthBackendError(
      `Unexpected SAC rpcproxy response: HTTP ${statusCode}`,
      { details: { statusCode, bodyText: bodyText.slice(0, 200) } }
    );
  }
}

function requireNonEmptyString(value, message) {
  if (typeof value !== "string" || value.trim() === "") {
    throw new TokenFormatError(message);
  }
  return value.trim();
}
