import { dirname } from "path";
import { mkdirSync } from "fs";
import { SYSTEM_OPENCLAW_CONFIG_PATH } from "./config";
import { readLooseConfigFile } from "./config-file";
import type { InstanceRecord } from "./instances";
import { fileExists, writeTextFile } from "./node-fs";
import { shouldUseSystemOpenclaw } from "./openclaw-platform";

/** 配置文件读取缓存：configPath -> { config, fetchedAt } */
const configCache = new Map<string, { config: Record<string, unknown>; fetchedAt: number }>();
const CONFIG_CACHE_TTL_MS = 5000; // 5 秒缓存

interface OriginSource {
  url: string;
  getHeader: (name: string) => string | null | undefined;
}

function normalizeOriginArray(value: unknown): string[] {
  if (!Array.isArray(value)) {
    return [];
  }

  return value.flatMap((item) => {
    if (typeof item !== "string") {
      return [];
    }
    return [item];
  });
}

function activeConfigPath(instance: InstanceRecord): string {
  return shouldUseSystemOpenclaw(instance.id)
    ? SYSTEM_OPENCLAW_CONFIG_PATH
    : instance.configPath;
}

async function readConfigFile(path: string): Promise<Record<string, unknown> | null> {
  const now = Date.now();
  const cached = configCache.get(path);

  if (cached && now - cached.fetchedAt < CONFIG_CACHE_TTL_MS) {
    return cached.config;
  }

  const config = await readLooseConfigFile(path);
  const result = Object.keys(config).length > 0 ? config : null;

  if (result) {
    configCache.set(path, { config: result, fetchedAt: now });
  }

  return result;
}

export async function ensureControlUiAllowedOrigins(
  instance: InstanceRecord,
  source: OriginSource
): Promise<boolean> {
  const configPath = activeConfigPath(instance);
  if (!(await fileExists(configPath))) {
    return false;
  }

  const config = (await readConfigFile(configPath)) || {};
  const gateway = (config.gateway as Record<string, unknown> | undefined) || {};
  const controlUi = (gateway.controlUi as Record<string, unknown> | undefined) || {};

  // Gateway is bound to loopback and only accessible through monitor proxy
  // Monitor handles all access control, so Gateway can trust all origins
  const nextAllowedOrigins = ["*"];
  const currentAllowedOrigins = normalizeOriginArray(controlUi.allowedOrigins);
  const unchanged = currentAllowedOrigins.length === 1 && currentAllowedOrigins[0] === "*";

  if (unchanged) {
    return false;
  }

  // 只更新 allowedOrigins，保留其他 controlUi 设置
  controlUi.allowedOrigins = nextAllowedOrigins;
  // 确保关键的安全设置不会被意外移除
  if (!controlUi.dangerouslyDisableDeviceAuth) {
    console.log("[control-ui] Adding dangerouslyDisableDeviceAuth=true to config");
    controlUi.dangerouslyDisableDeviceAuth = true;
  }
  if (!controlUi.allowInsecureAuth) {
    console.log("[control-ui] Adding allowInsecureAuth=true to config");
    controlUi.allowInsecureAuth = true;
  }

  gateway.controlUi = controlUi;
  config.gateway = gateway;

  console.log(`[control-ui] Writing config with controlUi:`, {
    enabled: controlUi.enabled,
    basePath: controlUi.basePath,
    allowInsecureAuth: controlUi.allowInsecureAuth,
    dangerouslyDisableDeviceAuth: controlUi.dangerouslyDisableDeviceAuth,
    allowedOrigins: nextAllowedOrigins,
  });

  mkdirSync(dirname(configPath), { recursive: true });
  await writeTextFile(configPath, JSON.stringify(config, null, 2));

  // 写入后清除缓存，确保下次读取到最新内容
  configCache.delete(configPath);

  return true;
}
