function normalizeOrigin(value: string | null | undefined): string | null {
  if (!value) {
    return null;
  }

  try {
    return new URL(value).origin;
  } catch {
    return null;
  }
}

export function requestTargetOrigin(request: Request): string {
  const url = new URL(request.url);
  const forwardedProto = request.headers.get("x-forwarded-proto")?.split(",")[0]?.trim();
  const forwardedHost = request.headers.get("x-forwarded-host")?.split(",")[0]?.trim();
  const host = forwardedHost || request.headers.get("host")?.split(",")[0]?.trim();

  if (host) {
    const protocol = (forwardedProto || url.protocol.replace(/:$/, "")).replace(/:$/, "");
    return `${protocol}://${host}`;
  }

  return url.origin;
}

export function requiresSameOrigin(request: Request): boolean {
  const method = request.method.toUpperCase();
  const upgrade = request.headers.get("upgrade")?.toLowerCase();
  if (upgrade === "websocket") {
    return true;
  }

  return !["GET", "HEAD", "OPTIONS"].includes(method);
}

export function isSameOriginRequest(request: Request): boolean {
  const origin = normalizeOrigin(request.headers.get("origin"));
  const target = requestTargetOrigin(request);

  if (origin) {
    return origin === target;
  }

  // 部分合法请求（如浏览器直接导航触发的 POST 表单）不携带 Origin，
  // 降级检查 Referer 的 origin 部分
  const refererOrigin = normalizeOrigin(request.headers.get("referer"));
  if (refererOrigin) {
    return refererOrigin === target;
  }

  // 两者都缺失，无法判定来源，拒绝
  return false;
}
