import { Hono } from "hono";
import { ensureDefaultInstance } from "../lib/instances";
import {
  getChannelPlugins,
  getChannelsConfig,
  installChannelPlugin,
  saveChannelsConfig,
  type InstallChannelPluginPayload,
  type SaveChannelsConfigPayload,
} from "../lib/channels";

const app = new Hono();

app.get("/config", async (c) => {
  try {
    console.log("[channels] reading config snapshot");
    return c.json(await getChannelsConfig(ensureDefaultInstance()));
  } catch (error: unknown) {
    console.error("[channels:error] failed to read config snapshot");
    console.error(error instanceof Error ? error.stack || error.message : String(error));
    return c.json(
      { message: error instanceof Error ? error.message : String(error) },
      500
    );
  }
});

app.get("/plugins", async (c) => {
  try {
    console.log("[channels] reading plugin status");
    return c.json(await getChannelPlugins(ensureDefaultInstance()));
  } catch (error: unknown) {
    console.error("[channels:error] failed to read plugin status");
    console.error(error instanceof Error ? error.stack || error.message : String(error));
    return c.json(
      { message: error instanceof Error ? error.message : String(error) },
      500
    );
  }
});

app.post("/config", async (c) => {
  try {
    const body = await c.req
      .json<SaveChannelsConfigPayload>()
      .catch(() => ({ feishu: null } as unknown as SaveChannelsConfigPayload));

    console.log(`[channels] saving channel config payload keys=${Object.keys(body || {}).join(",")}`);
    return c.json(await saveChannelsConfig(ensureDefaultInstance(), body));
  } catch (error: unknown) {
    console.error("[channels:error] failed to save channel config");
    console.error(error instanceof Error ? error.stack || error.message : String(error));
    return c.json(
      { message: error instanceof Error ? error.message : String(error) },
      400
    );
  }
});

app.post("/plugins/install", async (c) => {
  try {
    const body = await c.req
      .json<InstallChannelPluginPayload>()
      .then((payload) => {
        const legacyChannelId = (payload as { channelId?: InstallChannelPluginPayload["channelKey"] }).channelId;
        if (!payload.channelKey && legacyChannelId) {
          return { channelKey: legacyChannelId } as InstallChannelPluginPayload;
        }
        return payload;
      })
      .catch(() => ({ channelKey: "feishu" } as InstallChannelPluginPayload));

    console.log(`[channels] installing plugin for ${body.channelKey}`);
    return c.json(await installChannelPlugin(ensureDefaultInstance(), body));
  } catch (error: unknown) {
    console.error("[channels:error] failed to install channel plugin");
    console.error(error instanceof Error ? error.stack || error.message : String(error));
    return c.json(
      { message: error instanceof Error ? error.message : String(error) },
      400
    );
  }
});

export default app;
