import type { IncomingMessage, OutgoingHttpHeaders } from "node:http";
import type { Duplex } from "node:stream";
import { WebSocket, WebSocketServer } from "ws";
import type { RawData } from "ws";
import { DEFAULT_INSTANCE_ID, MONITOR_BASE_PATH } from "./config";
import { ensureControlUiAllowedOrigins } from "./control-ui";
import { ensureDefaultInstance, getInstance, type InstanceRecord } from "./instances";
import { readInstanceConfig, readInstancePort } from "./openclaw-instance";

const RESERVED_SEGMENTS = new Set(["api", "assets"]);

const tokenCache = new Map<string, { token: string | undefined; fetchedAt: number }>();
const TOKEN_CACHE_TTL_MS = 30_000;

const MAX_PENDING_MESSAGES = 500;
const PENDING_TIMEOUT_MS = 30_000;

const HOP_BY_HOP_HEADERS = [
  "connection",
  "keep-alive",
  "proxy-authenticate",
  "proxy-authorization",
  "te",
  "trailer",
  "transfer-encoding",
  "upgrade",
  "content-length",
];

const WEBSOCKET_INTERNAL_HEADERS = [
  "sec-websocket-extensions",
  "sec-websocket-key",
  "sec-websocket-protocol",
  "sec-websocket-version",
  "sec-websocket-accept",
];

type DownstreamMessage = string | Buffer;

const CONTROL_UI_SETTINGS_KEY = "openclaw.control.settings.v1";
const CONTROL_UI_TOKEN_KEY = "openclaw.control.token.v1";
const CONTROL_UI_TOKEN_PREFIX = "openclaw.control.token.v1:";

interface ProxyWebSocketState {
  targetUrl: string;
  headers: OutgoingHttpHeaders;
  protocols?: string[];
  authToken?: string;
  upstream?: WebSocket;
  pendingMessages: DownstreamMessage[];
  connectStartedAt: number;
}

interface ProxyTarget {
  instance: InstanceRecord;
  port: number;
  upstreamHttpUrl: URL;
  upstreamWsUrl: string;
  requestUrl: URL;
  authToken?: string;
}

const downstreamWss = new WebSocketServer({ noServer: true });

function splitPath(pathname: string): string[] {
  return pathname.split("/").filter(Boolean);
}

function matchProxyInstanceId(pathname: string): string | null {
  const baseSegments = splitPath(MONITOR_BASE_PATH);
  const segments = splitPath(pathname);

  if (segments.length <= baseSegments.length) {
    return null;
  }

  for (let index = 0; index < baseSegments.length; index += 1) {
    if (segments[index] !== baseSegments[index]) {
      return null;
    }
  }

  const instanceId = segments[baseSegments.length];
  if (!instanceId || RESERVED_SEGMENTS.has(instanceId)) {
    return null;
  }

  return instanceId;
}

function isWebSocketRequest(request: Request): boolean {
  return request.headers.get("upgrade")?.toLowerCase() === "websocket";
}

async function resolveInstance(instanceId: string): Promise<InstanceRecord | null> {
  if (instanceId === DEFAULT_INSTANCE_ID) {
    return ensureDefaultInstance();
  }
  return getInstance(instanceId);
}

async function resolveGatewayToken(instance: InstanceRecord): Promise<string | undefined> {
  if (typeof process.env.OPENCLAW_GATEWAY_TOKEN === "string" && process.env.OPENCLAW_GATEWAY_TOKEN.length > 0) {
    return process.env.OPENCLAW_GATEWAY_TOKEN;
  }

  const now = Date.now();
  const cached = tokenCache.get(instance.id);
  if (cached && now - cached.fetchedAt < TOKEN_CACHE_TTL_MS) {
    return cached.token;
  }

  try {
    const config = await readInstanceConfig(instance);
    const gateway = (config.gateway as Record<string, unknown> | undefined) || {};
    const auth = (gateway.auth as Record<string, unknown> | undefined) || {};
    const token = typeof auth.token === "string" && auth.token.length > 0 ? auth.token : undefined;

    tokenCache.set(instance.id, { token, fetchedAt: now });
    return token;
  } catch {
    return undefined;
  }
}

async function resolveProxyTarget(request: Request): Promise<ProxyTarget | Response | null> {
  const requestUrl = new URL(request.url);
  const instanceId = matchProxyInstanceId(requestUrl.pathname);
  if (!instanceId) {
    return null;
  }

  const instance = await resolveInstance(instanceId);
  if (!instance) {
    return new Response(`OpenClaw instance not found: ${instanceId}`, { status: 404 });
  }

  await ensureControlUiAllowedOrigins(instance, {
    url: request.url,
    getHeader: (name) => request.headers.get(name),
  });

  const port = (await readInstancePort(instance)) ?? instance.gatewayPort;
  if (!port) {
    return new Response(`OpenClaw instance is not configured: ${instanceId}`, { status: 502 });
  }

  const authToken = await resolveGatewayToken(instance);

  return {
    instance,
    port,
    upstreamHttpUrl: new URL(
      `${requestUrl.pathname}${requestUrl.search}`,
      `http://127.0.0.1:${port}`
    ),
    upstreamWsUrl: `ws://127.0.0.1:${port}${requestUrl.pathname}${requestUrl.search}`,
    requestUrl,
    authToken,
  };
}

function stripPort(host: string): string {
  try {
    return new URL(`http://${host}`).hostname;
  } catch {
    return host;
  }
}

function forwardedForValue(request: Request, clientIp?: string): string | null {
  const existing = request.headers.get("x-forwarded-for")?.trim();
  if (existing && clientIp) {
    return `${existing}, ${clientIp}`;
  }
  return existing || clientIp || null;
}

function buildBaseProxyHeaders(
  request: Request,
  port: number,
  proxyBasePath: string,
  clientIp?: string
): Headers {
  const requestUrl = new URL(request.url);
  const headers = new Headers(request.headers);
  const forwardedProto =
    request.headers.get("x-forwarded-proto")?.split(",")[0]?.trim() ||
    requestUrl.protocol.replace(/:$/, "");
  const forwardedHost =
    request.headers.get("x-forwarded-host")?.split(",")[0]?.trim() ||
    request.headers.get("host") ||
    requestUrl.host;
  const forwardedPort = requestUrl.port || (forwardedProto === "https" ? "443" : "80");
  const forwardedFor = forwardedForValue(request, clientIp);

  headers.set("host", `127.0.0.1:${port}`);
  headers.set("x-forwarded-host", forwardedHost);
  headers.set("x-forwarded-proto", forwardedProto);
  headers.set("x-forwarded-port", forwardedPort);
  headers.set("x-forwarded-prefix", proxyBasePath);
  headers.set("x-forwarded-uri", `${requestUrl.pathname}${requestUrl.search}`);
  headers.set("x-real-ip", clientIp || stripPort(forwardedHost));

  if (forwardedFor) {
    headers.set("x-forwarded-for", forwardedFor);
  }

  for (const headerName of HOP_BY_HOP_HEADERS) {
    headers.delete(headerName);
  }

  return headers;
}

function buildProxyRequest(
  request: Request,
  target: ProxyTarget,
  clientIp?: string
): Request {
  const headers = buildBaseProxyHeaders(
    request,
    target.port,
    target.instance.proxyBasePath,
    clientIp
  );

  const init: RequestInit & { duplex?: "half" } = {
    method: request.method,
    headers,
    redirect: "manual",
    signal: request.signal,
  };

  if (request.method !== "GET" && request.method !== "HEAD") {
    init.body = request.body;
    init.duplex = "half";
  }

  return new Request(target.upstreamHttpUrl.toString(), init);
}

function rewriteLocationHeader(
  responseHeaders: Headers,
  upstreamOrigin: string,
  requestOrigin: string
): void {
  const location = responseHeaders.get("location");
  if (!location) {
    return;
  }

  try {
    const resolved = new URL(location, upstreamOrigin);
    if (resolved.origin !== upstreamOrigin) {
      return;
    }

    const rewritten = new URL(
      `${resolved.pathname}${resolved.search}${resolved.hash}`,
      `${requestOrigin}/`
    );
    responseHeaders.set("location", rewritten.toString());
  } catch {
    // ignore invalid location values
  }
}

function controlUiBootstrapScript(proxyBasePath: string): string {
  const serializedBasePath = JSON.stringify(proxyBasePath);
  const serializedSettingsKey = JSON.stringify(CONTROL_UI_SETTINGS_KEY);
  const serializedTokenKey = JSON.stringify(CONTROL_UI_TOKEN_KEY);
  const serializedTokenPrefix = JSON.stringify(CONTROL_UI_TOKEN_PREFIX);

  return [
    "<script>",
    `window.__OPENCLAW_CONTROL_UI_BASE_PATH__ = ${serializedBasePath};`,
    "(() => {",
    "  try {",
    `    const settingsKey = ${serializedSettingsKey};`,
    "    const raw = window.localStorage.getItem(settingsKey);",
    "    if (raw) {",
    "      try {",
    "        const parsed = JSON.parse(raw);",
    "        if (parsed && typeof parsed === 'object') {",
    "          delete parsed.gatewayUrl;",
    "          delete parsed.token;",
    "          window.localStorage.setItem(settingsKey, JSON.stringify(parsed));",
    "        } else {",
    "          window.localStorage.removeItem(settingsKey);",
    "        }",
    "      } catch {",
    "        window.localStorage.removeItem(settingsKey);",
    "      }",
    "    }",
    "  } catch {}",
    "  try {",
    "    const storage = window.sessionStorage;",
    `    storage.removeItem(${serializedTokenKey});`,
    "    for (let index = storage.length - 1; index >= 0; index -= 1) {",
    "      const key = storage.key(index);",
    `      if (key && key.indexOf(${serializedTokenPrefix}) === 0) {`,
    "        storage.removeItem(key);",
    "      }",
    "    }",
    "  } catch {}",
    "})();",
    "</script>",
  ].join("");
}

function injectControlUiBootstrap(html: string, proxyBasePath: string): string {
  const script = controlUiBootstrapScript(proxyBasePath);

  if (html.includes("<script type=\"module\"")) {
    return html.replace("<script type=\"module\"", `${script}<script type="module"`);
  }

  if (html.includes("</head>")) {
    return html.replace("</head>", `${script}</head>`);
  }

  return `${script}${html}`;
}

function formatUpstreamFetchError(error: unknown): string {
  if (error instanceof Error) {
    const cause = error.cause as { code?: string; message?: string } | undefined;
    if (cause?.code && cause?.message) {
      return `${error.message} (${cause.code}: ${cause.message})`;
    }
    if (cause?.code) {
      return `${error.message} (${cause.code})`;
    }
    return error.message;
  }
  return String(error);
}

function sanitizeCloseReason(reason: string): string {
  const trimmed = reason.trim();
  if (!trimmed) {
    return "";
  }
  return trimmed.length > 120 ? trimmed.slice(0, 120) : trimmed;
}

function shouldPatchConnectMessage(payload: unknown): payload is Record<string, unknown> {
  if (!payload || typeof payload !== "object" || Array.isArray(payload)) {
    return false;
  }

  const record = payload as Record<string, unknown>;
  return record.type === "connect" || record.op === "connect" || record.method === "connect";
}

function injectAuthTokenIntoMessage(message: DownstreamMessage, authToken?: string): DownstreamMessage {
  if (!authToken || typeof message !== "string") {
    return message;
  }

  try {
    const payload = JSON.parse(message) as unknown;
    if (!shouldPatchConnectMessage(payload)) {
      return message;
    }

    const params = (payload.params && typeof payload.params === "object" && !Array.isArray(payload.params))
      ? payload.params as Record<string, unknown>
      : {};
    const auth = (params.auth && typeof params.auth === "object" && !Array.isArray(params.auth))
      ? params.auth as Record<string, unknown>
      : {};

    if (typeof auth.token === "string" && auth.token.length > 0) {
      return message;
    }

    auth.token = authToken;
    params.auth = auth;
    payload.params = params;
    return JSON.stringify(payload);
  } catch {
    return message;
  }
}

function normalizeRawData(data: RawData, isBinary: boolean): DownstreamMessage {
  if (!isBinary && typeof data === "string") {
    return data;
  }

  if (Array.isArray(data)) {
    const chunks = data as Array<Buffer | ArrayBuffer>;
    return Buffer.concat(chunks.map((chunk) => Buffer.isBuffer(chunk) ? chunk : Buffer.from(new Uint8Array(chunk))));
  }

  if (typeof data === "string") {
    return Buffer.from(data);
  }

  return Buffer.isBuffer(data) ? data : Buffer.from(new Uint8Array(data));
}

function rawDataToText(data: RawData): string {
  if (typeof data === "string") {
    return data;
  }

  if (Array.isArray(data)) {
    const chunks = data as Array<Buffer | ArrayBuffer>;
    return Buffer.concat(
      chunks.map((chunk) => Buffer.isBuffer(chunk) ? chunk : Buffer.from(new Uint8Array(chunk)))
    ).toString("utf8");
  }

  return Buffer.from(new Uint8Array(data)).toString("utf8");
}

function forwardMessageToUpstream(
  upstream: WebSocket,
  message: DownstreamMessage,
  authToken?: string
): void {
  const payload = injectAuthTokenIntoMessage(message, authToken);
  upstream.send(payload, { binary: typeof payload !== "string" });
}

function buildWebSocketHeaders(
  request: Request,
  target: ProxyTarget,
  clientIp?: string
): OutgoingHttpHeaders {
  const headers = buildBaseProxyHeaders(
    request,
    target.port,
    target.instance.proxyBasePath,
    clientIp
  );

  headers.delete("host");
  for (const headerName of WEBSOCKET_INTERNAL_HEADERS) {
    headers.delete(headerName);
  }

  const serialized: OutgoingHttpHeaders = {};
  for (const [key, value] of headers.entries()) {
    serialized[key] = value;
  }
  return serialized;
}

async function writeHttpResponse(socket: Duplex, response: Response): Promise<void> {
  const body = response.body ? Buffer.from(await response.arrayBuffer()) : Buffer.alloc(0);
  const headers = new Headers(response.headers);
  headers.set("Connection", "close");
  headers.set("Content-Length", String(body.length));

  const statusLine = `HTTP/1.1 ${response.status} ${response.statusText || "Error"}`;
  const headerLines = Array.from(headers.entries()).map(([key, value]) => `${key}: ${value}`);
  socket.write(`${statusLine}\r\n${headerLines.join("\r\n")}\r\n\r\n`);
  socket.end(body);
}

function createUpstreamWebSocket(state: ProxyWebSocketState): WebSocket {
  if (state.protocols && state.protocols.length > 0) {
    return new WebSocket(state.targetUrl, state.protocols, { headers: state.headers });
  }
  return new WebSocket(state.targetUrl, { headers: state.headers });
}

function closeUpstreamSocket(upstream: WebSocket | undefined, code?: number, reason?: string): void {
  if (!upstream || upstream.readyState >= WebSocket.CLOSING) {
    return;
  }
  upstream.close(code || 1000, sanitizeCloseReason(reason || ""));
}

function setupProxyWebSocketConnection(
  downstream: WebSocket,
  state: ProxyWebSocketState
): void {
  const upstream = createUpstreamWebSocket(state);
  state.upstream = upstream;

  upstream.on("open", () => {
    for (const message of state.pendingMessages) {
      forwardMessageToUpstream(upstream, message, state.authToken);
    }
    state.pendingMessages = [];
  });

  upstream.on("message", (data, isBinary) => {
    if (downstream.readyState !== WebSocket.OPEN) {
      return;
    }
    downstream.send(
      isBinary ? normalizeRawData(data, true) : rawDataToText(data),
      { binary: isBinary }
    );
  });

  upstream.on("close", (code, reason) => {
    state.upstream = undefined;
    if (downstream.readyState === WebSocket.OPEN || downstream.readyState === WebSocket.CONNECTING) {
      downstream.close(code || 1000, sanitizeCloseReason(rawDataToText(reason)));
    }
  });

  upstream.on("error", () => {
    if (downstream.readyState === WebSocket.OPEN || downstream.readyState === WebSocket.CONNECTING) {
      downstream.close(1011, "OpenClaw upstream socket error");
    }
  });

  downstream.on("message", (data, isBinary) => {
    const message = normalizeRawData(data, isBinary);
    const activeUpstream = state.upstream;
    if (!activeUpstream) {
      return;
    }

    if (activeUpstream.readyState === WebSocket.CONNECTING) {
      const now = Date.now();
      if (now - state.connectStartedAt > PENDING_TIMEOUT_MS) {
        console.warn(`[proxy-gateway] Upstream connection timeout (${PENDING_TIMEOUT_MS}ms), closing`);
        downstream.close(1008, "Upstream connection timeout");
        return;
      }

      if (state.pendingMessages.length >= MAX_PENDING_MESSAGES) {
        console.warn(`[proxy-gateway] Pending messages queue full (${MAX_PENDING_MESSAGES}), closing`);
        downstream.close(1008, "Pending messages queue overflow");
        return;
      }

      state.pendingMessages.push(message);
      return;
    }

    if (activeUpstream.readyState !== WebSocket.OPEN) {
      return;
    }

    forwardMessageToUpstream(activeUpstream, message, state.authToken);
  });

  downstream.on("close", (code, reason) => {
    state.upstream = undefined;
    closeUpstreamSocket(upstream, code, rawDataToText(reason));
  });

  downstream.on("error", () => {
    closeUpstreamSocket(upstream, 1011, "Monitor downstream socket error");
  });
}

export async function maybeProxyHttpRequest(
  request: Request,
  clientIp?: string
): Promise<Response | null> {
  const target = await resolveProxyTarget(request);
  if (!target) {
    return null;
  }
  if (target instanceof Response) {
    return target;
  }

  try {
    const upstreamResponse = await fetch(buildProxyRequest(request, target, clientIp));
    const responseHeaders = new Headers(upstreamResponse.headers);
    rewriteLocationHeader(
      responseHeaders,
      target.upstreamHttpUrl.origin,
      target.requestUrl.origin
    );

    const contentType = responseHeaders.get("content-type")?.toLowerCase() || "";
    if (contentType.includes("text/html")) {
      const html = await upstreamResponse.text();
      const patchedHtml = injectControlUiBootstrap(html, target.instance.proxyBasePath);
      responseHeaders.delete("content-length");
      responseHeaders.set("cache-control", "no-store");

      return new Response(patchedHtml, {
        status: upstreamResponse.status,
        statusText: upstreamResponse.statusText,
        headers: responseHeaders,
      });
    }

    return new Response(upstreamResponse.body, {
      status: upstreamResponse.status,
      statusText: upstreamResponse.statusText,
      headers: responseHeaders,
    });
  } catch (error: unknown) {
    const message = formatUpstreamFetchError(error);
    return new Response(`OpenClaw upstream request failed: ${message}`, {
      status: 502,
    });
  }
}

export async function maybeHandleProxyWebSocketUpgrade(
  request: Request,
  incoming: IncomingMessage,
  socket: Duplex,
  head: Buffer,
  clientIp?: string
): Promise<boolean> {
  if (!isWebSocketRequest(request)) {
    return false;
  }

  const target = await resolveProxyTarget(request);
  if (!target) {
    return false;
  }
  if (target instanceof Response) {
    await writeHttpResponse(socket, target);
    return true;
  }

  const protocols = request.headers
    .get("sec-websocket-protocol")
    ?.split(",")
    .map((value) => value.trim())
    .filter(Boolean);

  const state: ProxyWebSocketState = {
    targetUrl: target.upstreamWsUrl,
    headers: buildWebSocketHeaders(request, target, clientIp),
    protocols: protocols && protocols.length > 0 ? protocols : undefined,
    authToken: target.authToken,
    pendingMessages: [],
    connectStartedAt: Date.now(),
  };

  downstreamWss.handleUpgrade(incoming, socket, head, (downstream) => {
    setupProxyWebSocketConnection(downstream, state);
  });

  return true;
}
