import { TRIMSRV_COMMAND } from "./constants.js";
import { composeTrimSrvSessionId } from "./packet/trimsrv-packet.js";
import { createSessionSeed } from "./utils.js";

export class SessionFactory {
  #current = createSessionSeed();

  nextRpcSessionId() {
    this.#current += 1n;
    return this.#current;
  }

  nextTrimSrvSessionId(commandId = TRIMSRV_COMMAND.TOKEN_QUERY) {
    this.#current += 1n;
    return composeTrimSrvSessionId(this.#current, commandId);
  }
}
