import type { FnOsIdentity, MonitorAuthIdentity } from "./types";
import { MONITOR_BASE_PATH } from "../config";
import {
  FN_AUTH_COOKIE_NAME,
  FN_AUTH_ENABLED,
  FN_AUTH_ENTRY_COOKIE_NAME,
  FN_AUTH_REQUIRE_SAME_ORIGIN,
  isAuthBypassedPath,
} from "./config";
import { getCookieValue } from "./cookies";
import { verifyEntryToken, verifyFnOsToken } from "./fnos-auth-service";
import { forbiddenResponse, serviceUnavailableResponse, unauthorizedResponse } from "./responses";
import { isSameOriginRequest, requiresSameOrigin } from "./origin-guard";

const INVALID_FNOS_TOKEN_ERROR_NAMES = new Set([
  "InvalidFnOsTokenError",
  "TokenFormatError",
]);

const INVALID_ENTRY_TOKEN_ERROR_NAMES = new Set([
  "TokenFormatError",
]);

type AttemptFailureKind = "missing" | "invalid" | "backend_error";

interface AttemptSuccess {
  ok: true;
  identity: MonitorAuthIdentity;
}

interface AttemptFailure {
  ok: false;
  source: "fnos" | "entry";
  kind: AttemptFailureKind;
}

type AttemptResult = AttemptSuccess | AttemptFailure;

export interface AuthSuccessResult {
  ok: true;
  identity: MonitorAuthIdentity | null;
  bypassed: boolean;
}

export interface AuthFailureResult {
  ok: false;
  response: Response;
  reason: string;
}

export type AuthResult = AuthSuccessResult | AuthFailureResult;

function requestLabel(request: Request): string {
  const url = new URL(request.url);
  return `${request.method.toUpperCase()} ${url.pathname}`;
}

function originFailure(request: Request): AuthFailureResult {
  console.warn(`[auth] origin mismatch for ${requestLabel(request)}`);
  return {
    ok: false,
    reason: "origin_mismatch",
    response: forbiddenResponse(request, "origin_mismatch"),
  };
}

function splitPath(pathname: string): string[] {
  return pathname.split("/").filter(Boolean);
}

function isOpenClawProxyPath(pathname: string): boolean {
  const baseSegments = splitPath(MONITOR_BASE_PATH);
  const segments = splitPath(pathname);

  if (segments.length <= baseSegments.length) {
    return false;
  }

  for (let index = 0; index < baseSegments.length; index += 1) {
    if (segments[index] !== baseSegments[index]) {
      return false;
    }
  }

  const instanceId = segments[baseSegments.length];
  return Boolean(instanceId) && instanceId !== "api" && instanceId !== "assets";
}

function passesOriginGuard(request: Request): boolean {
  if (isOpenClawProxyPath(new URL(request.url).pathname)) {
    return true;
  }
  if (!FN_AUTH_REQUIRE_SAME_ORIGIN || !requiresSameOrigin(request)) {
    return true;
  }
  return isSameOriginRequest(request);
}

async function authenticateFnOsToken(request: Request, token: string): Promise<AttemptResult> {
  try {
    const result = await verifyFnOsToken(token);
    // SAC mode returns boolean, RPC mode returns FnOsIdentity (truthy object)
    if (!result) {
      console.warn(`[auth] invalid fnOS token for ${requestLabel(request)}`);
      return { ok: false, source: "fnos", kind: "invalid" };
    }
    const identity: MonitorAuthIdentity =
      typeof result === "object"
        ? { kind: "fnos", user: result as FnOsIdentity }
        : { kind: "fnos" } as MonitorAuthIdentity;
    return { ok: true, identity };
  } catch (error) {
    const name = error instanceof Error ? error.name : "UnknownAuthError";
    const message = error instanceof Error ? error.message : String(error);

    if (INVALID_FNOS_TOKEN_ERROR_NAMES.has(name)) {
      console.warn(`[auth] invalid fnOS token for ${requestLabel(request)}: ${name}`);
      return {
        ok: false,
        source: "fnos",
        kind: "invalid",
      };
    }

    console.error(`[auth] fnOS token verification failed for ${requestLabel(request)}: ${name}: ${message}`);
    return {
      ok: false,
      source: "fnos",
      kind: "backend_error",
    };
  }
}

async function authenticateEntryToken(request: Request, token: string): Promise<AttemptResult> {
  try {
    const valid = await verifyEntryToken(token);
    if (valid) {
      return {
        ok: true,
        identity: {
          kind: "entry",
        },
      };
    }

    console.warn(`[auth] invalid entry-token for ${requestLabel(request)}`);
    return {
      ok: false,
      source: "entry",
      kind: "invalid",
    };
  } catch (error) {
    const name = error instanceof Error ? error.name : "UnknownAuthError";
    const message = error instanceof Error ? error.message : String(error);

    if (INVALID_ENTRY_TOKEN_ERROR_NAMES.has(name)) {
      console.warn(`[auth] invalid entry-token for ${requestLabel(request)}: ${name}`);
      return {
        ok: false,
        source: "entry",
        kind: "invalid",
      };
    }

    console.error(`[auth] entry-token verification failed for ${requestLabel(request)}: ${name}: ${message}`);
    return {
      ok: false,
      source: "entry",
      kind: "backend_error",
    };
  }
}

function missingFailure(source: "fnos" | "entry"): AttemptFailure {
  return {
    ok: false,
    source,
    kind: "missing",
  };
}

export async function authenticateRequest(request: Request): Promise<AuthResult> {
  const url = new URL(request.url);

  if (!FN_AUTH_ENABLED) {
    return {
      ok: true,
      identity: null,
      bypassed: true,
    };
  }

  if (isAuthBypassedPath(url.pathname, request.method.toUpperCase())) {
    return {
      ok: true,
      identity: null,
      bypassed: true,
    };
  }

  const fnosToken = getCookieValue(request, FN_AUTH_COOKIE_NAME);
  const entryToken = getCookieValue(request, FN_AUTH_ENTRY_COOKIE_NAME);
  const failures: AttemptFailure[] = [];

  if (fnosToken) {
    const fnosResult = await authenticateFnOsToken(request, fnosToken);
    if (fnosResult.ok) {
      if (!passesOriginGuard(request)) {
        return originFailure(request);
      }
      return {
        ok: true,
        identity: fnosResult.identity,
        bypassed: false,
      };
    }
    failures.push(fnosResult);
  } else {
    failures.push(missingFailure("fnos"));
  }

  if (entryToken) {
    const entryResult = await authenticateEntryToken(request, entryToken);
    if (entryResult.ok) {
      if (!passesOriginGuard(request)) {
        return originFailure(request);
      }
      return {
        ok: true,
        identity: entryResult.identity,
        bypassed: false,
      };
    }
    failures.push(entryResult);
  } else {
    failures.push(missingFailure("entry"));
  }

  const hasBackendError = failures.some((failure) => failure.kind === "backend_error");
  const hasCredential = Boolean(fnosToken) || Boolean(entryToken);

  if (!hasCredential) {
    console.warn(
      `[auth] missing ${FN_AUTH_COOKIE_NAME} and ${FN_AUTH_ENTRY_COOKIE_NAME} for ${requestLabel(request)}`
    );
    return {
      ok: false,
      reason: "missing_credentials",
      response: unauthorizedResponse(request, "missing_credentials"),
    };
  }

  if (hasBackendError) {
    return {
      ok: false,
      reason: "auth_backend_error",
      response: serviceUnavailableResponse(request, "auth_backend_error"),
    };
  }

  return {
    ok: false,
    reason: "invalid_token",
    response: unauthorizedResponse(request, "invalid_token"),
  };
}
