import { mkdirSync } from "fs";
import { homedir } from "os";
import { SYSTEM_OPENCLAW_CONFIG_PATH } from "./config";
import { readLooseConfigFile } from "./config-file";
import type { InstanceRecord } from "./instances";
import { fileExists, readTextFile, writeTextFile } from "./node-fs";
import { managedOpenclawBinPath, prependToPath, resolveSystemOpenclawBinary, shouldUseSystemOpenclaw } from "./openclaw-platform";

export function usesSystemOpenclaw(instance: InstanceRecord): boolean {
  return shouldUseSystemOpenclaw(instance.id);
}

export function activeConfigPath(instance: InstanceRecord): string {
  return usesSystemOpenclaw(instance)
    ? SYSTEM_OPENCLAW_CONFIG_PATH
    : instance.configPath;
}

export function openclawEnv(instance: InstanceRecord): Record<string, string | undefined> {
  const configPath = activeConfigPath(instance);

  if (usesSystemOpenclaw(instance)) {
    return {
      ...process.env,
      HOME: process.env.HOME || homedir(),
      OPENCLAW_CONFIG_PATH: configPath,
    };
  }

  return {
    ...process.env,
    HOME: instance.homeDir,
    OPENCLAW_CONFIG_PATH: configPath,
    PATH: prependToPath(process.env.PATH, `${instance.installDir}/node_modules/.bin`),
  };
}

export function openclawBinPath(instance: InstanceRecord): string {
  if (usesSystemOpenclaw(instance)) {
    return "openclaw";
  }
  return managedOpenclawBinPath(instance.installDir);
}

export async function resolveOpenclawBinary(instance: InstanceRecord): Promise<string | null> {
  if (usesSystemOpenclaw(instance)) {
    return resolveSystemOpenclawBinary();
  }

  const managedBin = openclawBinPath(instance);
  return (await fileExists(managedBin)) ? managedBin : null;
}

export async function requireOpenclawBinary(instance: InstanceRecord): Promise<string> {
  const resolved = await resolveOpenclawBinary(instance);
  if (!resolved) {
    throw new Error("openclaw binary not found");
  }
  return resolved;
}

export function openclawSpawnCwd(instance: InstanceRecord): string | undefined {
  return usesSystemOpenclaw(instance) ? void 0 : instance.installDir;
}

export async function ensureInstanceDirectories(instance: InstanceRecord): Promise<void> {
  mkdirSync(instance.installDir, { recursive: true });
  mkdirSync(instance.homeDir, { recursive: true });
  mkdirSync(instance.runtimeDir, { recursive: true });
  mkdirSync(instance.stateDir, { recursive: true });
  mkdirSync(instance.workspaceDir, { recursive: true });
  mkdirSync(`${instance.homeDir}/.openclaw`, { recursive: true });
}

async function readJsonFile(path: string): Promise<Record<string, unknown> | null> {
  try {
    const config = await readLooseConfigFile(path);
    if (Object.keys(config).length > 0) {
      return config;
    }
  } catch {
    return null;
  }
  return null;
}

async function readSystemOpenclawConfig(): Promise<Record<string, unknown> | null> {
  return readJsonFile(SYSTEM_OPENCLAW_CONFIG_PATH);
}

function readGatewayPortFromConfig(config: Record<string, unknown> | null): number | null {
  const gateway = (config?.gateway as Record<string, unknown> | undefined) || {};
  const port = gateway.port;
  return typeof port === "number" && Number.isFinite(port) ? port : null;
}

export async function readInstancePort(instance: InstanceRecord): Promise<number | null> {
  if (usesSystemOpenclaw(instance)) {
    const systemPort = readGatewayPortFromConfig(await readSystemOpenclawConfig());
    if (systemPort) {
      return systemPort;
    }
    return null;
  }

  try {
    if (await fileExists(instance.envPath)) {
      const content = await readTextFile(instance.envPath);
      const match = content.match(/^PORT=(\d+)/m);
      if (match) {
        return parseInt(match[1], 10);
      }
    }
  } catch {
    return null;
  }

  return null;
}

export async function writeInstancePort(instance: InstanceRecord, port: number): Promise<void> {
  if (usesSystemOpenclaw(instance)) {
    const config = (await readSystemOpenclawConfig()) || {};
    const gateway = (config.gateway as Record<string, unknown> | undefined) || {};
    gateway.port = port;
    config.gateway = gateway;
    await writeTextFile(activeConfigPath(instance), JSON.stringify(config, null, 2));
    return;
  }

  await ensureInstanceDirectories(instance);
  await writeTextFile(instance.envPath, `PORT=${port}\n`);
}

export async function readInstanceConfig(instance: InstanceRecord): Promise<Record<string, unknown>> {
  const config = await readJsonFile(activeConfigPath(instance));
  if (config) {
    return config;
  }

  return {};
}

export async function writeInstanceConfig(instance: InstanceRecord, config: Record<string, unknown>): Promise<void> {
  if (!usesSystemOpenclaw(instance)) {
    await ensureInstanceDirectories(instance);
  }
  await writeTextFile(activeConfigPath(instance), JSON.stringify(config, null, 2));
}
