import { DatabaseSync } from "node:sqlite";
import { mkdirSync } from "fs";
import { DEFAULT_INSTANCE_ID, DATA_ROOT, MONITOR_DB_DIR, MONITOR_DB_PATH, buildInstanceProxyBasePath } from "./config";

export interface InstanceRecord {
  id: string;
  ownerId: string;
  displayName: string;
  status: string;
  gatewayPort: number | null;
  proxyBasePath: string;
  dataRoot: string;
  installDir: string;
  homeDir: string;
  stateDir: string;
  workspaceDir: string;
  runtimeDir: string;
  configPath: string;
  envPath: string;
  logPath: string;
  pidPath: string;
  createdAt: string;
  updatedAt: string;
}

interface InstanceRow {
  id: string;
  owner_id: string;
  display_name: string;
  status: string;
  gateway_port: number | null;
  proxy_base_path: string;
  data_root: string;
  install_dir: string;
  home_dir: string;
  state_dir: string;
  workspace_dir: string;
  runtime_dir: string;
  config_path: string;
  env_path: string;
  log_path: string;
  pid_path: string;
  created_at: string;
  updated_at: string;
}

let db: DatabaseSync | null = null;

function getDb(): DatabaseSync {
  if (db) {
    return db;
  }

  mkdirSync(MONITOR_DB_DIR, { recursive: true });
  db = new DatabaseSync(MONITOR_DB_PATH);
  db.exec(`
    CREATE TABLE IF NOT EXISTS instances (
      id TEXT PRIMARY KEY,
      owner_id TEXT NOT NULL,
      display_name TEXT NOT NULL,
      status TEXT NOT NULL,
      gateway_port INTEGER,
      proxy_base_path TEXT NOT NULL,
      data_root TEXT NOT NULL,
      install_dir TEXT NOT NULL,
      home_dir TEXT NOT NULL,
      state_dir TEXT NOT NULL,
      workspace_dir TEXT NOT NULL,
      runtime_dir TEXT NOT NULL,
      config_path TEXT NOT NULL,
      env_path TEXT NOT NULL,
      log_path TEXT NOT NULL,
      pid_path TEXT NOT NULL,
      created_at TEXT NOT NULL,
      updated_at TEXT NOT NULL
    );
    CREATE INDEX IF NOT EXISTS idx_instances_owner_id ON instances(owner_id);
    CREATE UNIQUE INDEX IF NOT EXISTS idx_instances_proxy_base_path ON instances(proxy_base_path);
  `);
  return db;
}

function nowIso(): string {
  return new Date().toISOString();
}

function toRecord(row: InstanceRow): InstanceRecord {
  return {
    id: row.id,
    ownerId: row.owner_id,
    displayName: row.display_name,
    status: row.status,
    gatewayPort: row.gateway_port,
    proxyBasePath: row.proxy_base_path,
    dataRoot: row.data_root,
    installDir: row.install_dir,
    homeDir: row.home_dir,
    stateDir: row.state_dir,
    workspaceDir: row.workspace_dir,
    runtimeDir: row.runtime_dir,
    configPath: row.config_path,
    envPath: row.env_path,
    logPath: row.log_path,
    pidPath: row.pid_path,
    createdAt: row.created_at,
    updatedAt: row.updated_at,
  };
}

function buildDefaultInstance(): InstanceRecord {
  const createdAt = nowIso();
  const installDir = `${DATA_ROOT}/openclaw`;
  const homeDir = `${DATA_ROOT}/home`;
  const runtimeDir = `${DATA_ROOT}/runtime`;

  return {
    id: DEFAULT_INSTANCE_ID,
    ownerId: "system",
    displayName: "Default Gateway",
    status: "managed",
    gatewayPort: null,
    proxyBasePath: buildInstanceProxyBasePath(DEFAULT_INSTANCE_ID),
    dataRoot: DATA_ROOT,
    installDir,
    homeDir,
    stateDir: `${DATA_ROOT}/state`,
    workspaceDir: `${DATA_ROOT}/workspace`,
    runtimeDir,
    configPath: `${homeDir}/.openclaw/openclaw.json`,
    envPath: `${installDir}/.env`,
    logPath: `${installDir}/gateway.log`,
    pidPath: `${runtimeDir}/gateway.pid`,
    createdAt,
    updatedAt: createdAt,
  };
}

function buildDedicatedInstance(id: string, ownerId: string, displayName: string): InstanceRecord {
  const createdAt = nowIso();
  const dataRoot = `${DATA_ROOT}/instances/${id}`;
  const installDir = `${dataRoot}/openclaw`;
  const homeDir = `${dataRoot}/home`;
  const runtimeDir = `${dataRoot}/runtime`;

  return {
    id,
    ownerId,
    displayName,
    status: "created",
    gatewayPort: null,
    proxyBasePath: buildInstanceProxyBasePath(id),
    dataRoot,
    installDir,
    homeDir,
    stateDir: `${dataRoot}/state`,
    workspaceDir: `${dataRoot}/workspace`,
    runtimeDir,
    configPath: `${homeDir}/.openclaw/openclaw.json`,
    envPath: `${runtimeDir}/gateway.env`,
    logPath: `${runtimeDir}/gateway.log`,
    pidPath: `${runtimeDir}/gateway.pid`,
    createdAt,
    updatedAt: createdAt,
  };
}

function persistInstance(record: InstanceRecord): void {
  const database = getDb();
  database
    .prepare(`
      INSERT INTO instances (
        id, owner_id, display_name, status, gateway_port, proxy_base_path,
        data_root, install_dir, home_dir, state_dir, workspace_dir, runtime_dir,
        config_path, env_path, log_path, pid_path, created_at, updated_at
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
      ON CONFLICT(id) DO UPDATE SET
        owner_id = excluded.owner_id,
        display_name = excluded.display_name,
        status = excluded.status,
        gateway_port = excluded.gateway_port,
        proxy_base_path = excluded.proxy_base_path,
        data_root = excluded.data_root,
        install_dir = excluded.install_dir,
        home_dir = excluded.home_dir,
        state_dir = excluded.state_dir,
        workspace_dir = excluded.workspace_dir,
        runtime_dir = excluded.runtime_dir,
        config_path = excluded.config_path,
        env_path = excluded.env_path,
        log_path = excluded.log_path,
        pid_path = excluded.pid_path,
        updated_at = excluded.updated_at
    `)
    .run(
      record.id,
      record.ownerId,
      record.displayName,
      record.status,
      record.gatewayPort,
      record.proxyBasePath,
      record.dataRoot,
      record.installDir,
      record.homeDir,
      record.stateDir,
      record.workspaceDir,
      record.runtimeDir,
      record.configPath,
      record.envPath,
      record.logPath,
      record.pidPath,
      record.createdAt,
      record.updatedAt
    );
}

function generateInstanceId(ownerId: string): string {
  const normalizedOwner = ownerId.trim().toLowerCase().replace(/[^a-z0-9_-]+/g, "-").replace(/^-+|-+$/g, "");
  const suffix = crypto.randomUUID().slice(0, 8);
  return `gw_${normalizedOwner || "user"}_${suffix}`;
}

export function ensureDefaultInstance(): InstanceRecord {
  const existing = getInstance(DEFAULT_INSTANCE_ID);
  if (existing) {
    return existing;
  }

  const record = buildDefaultInstance();
  persistInstance(record);
  return record;
}

export function listInstances(): InstanceRecord[] {
  ensureDefaultInstance();
  const database = getDb();
  const rows = database
    .prepare(`SELECT * FROM instances ORDER BY created_at ASC`)
    .all() as unknown as InstanceRow[];
  return rows.map((row) => toRecord(row));
}

export function getInstance(id: string): InstanceRecord | null {
  const database = getDb();
  const row = database
    .prepare(`SELECT * FROM instances WHERE id = ? LIMIT 1`)
    .get(id) as InstanceRow | undefined;
  return row ? toRecord(row) : null;
}

export function createInstance(input: { ownerId: string; displayName?: string }): InstanceRecord {
  ensureDefaultInstance();
  const id = generateInstanceId(input.ownerId);
  const record = buildDedicatedInstance(id, input.ownerId.trim(), input.displayName?.trim() || `${input.ownerId.trim()} Gateway`);
  persistInstance(record);
  return record;
}

export function updateInstance(instanceId: string, patch: Partial<Pick<InstanceRecord, "status" | "gatewayPort" | "displayName">>): InstanceRecord | null {
  const current = getInstance(instanceId);
  if (!current) {
    return null;
  }

  const next: InstanceRecord = {
    ...current,
    ...patch,
    updatedAt: nowIso(),
  };
  persistInstance(next);
  return next;
}
